"use strict";
/* ================= state ================= */
var LOGO = "data:image/png;base64,";
var STORE_KEY = "leak-workorders-v1";
/* Esri World Imagery's own service schema declares LODs up to zoom 23, but
   real per-location coverage that deep is "select metropolitan areas" only
   (per Esri's own service description) — elsewhere the server just repeats
   the same already-fetched tile beyond its true native resolution. Verified
   directly against live tiles at a real (non-major-metro) job site: zoom 20
   was still genuinely distinct imagery; 21/22/23 came back byte-identical
   (same tile repeated), confirming 20 as a broadly-safe real ceiling.
   maxNativeZoom stops Leaflet from re-fetching those redundant deeper tiles
   over the network (faster/no wasted mobile data), while a higher maxZoom
   still lets a tech pinch-zoom further on a large roof — Leaflet just
   enlarges the last real tile via CSS instead of re-requesting a blank one,
   giving bigger, easier-to-tap targets for precise pin placement even where
   the underlying imagery doesn't get any sharper. Shared by the pin modal,
   asset modal, and building-history roof map — all satellite mode. */
var SAT_MAX_NATIVE_ZOOM = 20;
/* Mark: his RTK ortho is ~2cm/pixel -- vastly more detail than satellite
   tiles top out at (SAT_MAX_NATIVE_ZOOM above is the real, empirically-
   verified Esri ceiling). An ortho/GeoTIFF overlay itself never raises the
   MAP's own zoom ceiling in Leaflet -- L.imageOverlay and GeoRasterLayer
   aren't zoom-bound tile layers with a maxZoom of their own, so whichever
   BASE tile layer happens to be showing underneath (RoofMapper's satellite
   at 22, or its default OSM view at 20) is what silently capped how far in
   a tech could zoom even with the ortho loaded on top -- exactly what was
   blocking precision corner placement now that all tracing is by hand.
   See rmUpdateMapZoomCap() and "Ortho zoom cap" in DEV_NOTES.md. */
var RM_ORTHO_MAX_ZOOM = 26;
/* ================= cloud sync (Firebase Firestore) =================
   Environment-aware project selection (Firebase split, 2026-07-11): the app
   is static with no build step, so which Firebase project it talks to is
   decided entirely at RUNTIME, off window.location.hostname -- there's no
   other lever available (no env vars reach client-side static files).
   Production (leak-work-orders.netlify.app, deployed from main) stays on
   the original `watkins-service-orders` project -- Mark's real data,
   photos, owner account, published rules, all untouched. Dev (branch
   deploys, "dev--..." hostnames) and any local/preview environment move to
   a separate, empty `watkins-service-orders-dev` sandbox project, so dev
   work can never touch production's real Firestore/Storage/Auth again --
   the "Shared Firestore, dev/prod risk boundary" constraint that shaped
   several earlier auth-phase decisions (see docs/AUTH_DESIGN.md) is gone
   entirely once this is live, not just carefully worked around.
   Both configs are the public Firebase Web SDK config (apiKey included) --
   safe to commit, matching Firebase's own documented design: this key
   identifies the project to Google's servers, it does not grant access on
   its own (Firestore/Storage rules are what actually gate access). */
function isDevEnvironment(){
  var h = window.location.hostname;
  return h.indexOf("dev--") !== -1 || h === "localhost" || h === "127.0.0.1" || h.indexOf("deploy-preview-") !== -1;
}
var FIREBASE_CONFIG_PROD = {
  apiKey: "AIzaSyBZRMpIWde-6DPpg7yAvNOqJAQF5ZBxlAg",
  authDomain: "watkins-service-orders.firebaseapp.com",
  projectId: "watkins-service-orders",
  storageBucket: "watkins-service-orders.firebasestorage.app",
  messagingSenderId: "806263881954",
  appId: "1:806263881954:web:16fb8f9cfac591dce25ebb"
};
// watkins-service-orders-dev -- real project, created 2026-07-11 (Firestore
// Native/us-central1/production rules mirroring prod exactly, Email/Password
// enabled, dev--leak-work-orders.netlify.app authorized). Web config is
// public client config, same as production's below -- safe to commit.
// Cloud Storage on this project is NOT yet enabled (requires Blaze; the
// project is currently on Spark) -- see "Dev Storage requires Blaze" in
// DEV_NOTES.md for how photo upload fails on dev until that's attached.
var FIREBASE_CONFIG_DEV = {
  apiKey: "AIzaSyCuL04xUkChHjtQe4ros6SG_AOIXLyspTw",
  authDomain: "watkins-service-orders-dev.firebaseapp.com",
  projectId: "watkins-service-orders-dev",
  storageBucket: "watkins-service-orders-dev.firebasestorage.app",
  messagingSenderId: "815497932675",
  appId: "1:815497932675:web:54165e8a0f0f3dde8110b6"
};
/* CRITICAL SAFETY GUARD, added after a real incident: shipping the dev/prod
   switch below ONCE ALREADY broke dev sign-in outright (auth/api-key-not-valid)
   because FIREBASE_CONFIG_DEV was still a placeholder when it deployed --
   there is no partial-credit state for "almost a real API key." This guard
   now checks actual SHAPE, not just "did someone edit the placeholder
   string" -- a real Firebase Web apiKey always starts "AIza", a real
   messagingSenderId is all digits, a real appId always contains ":" -- so a
   truncated paste, a swapped field, or any other malformed value fails
   closed exactly like an untouched placeholder does, falling back to
   production rather than presenting a broken login screen. A clear console
   warning marks the fallback so it's never mistaken for the real split
   being live. */
function devFirebaseConfigIsReal(){
  var c = FIREBASE_CONFIG_DEV;
  return !!c.projectId && c.projectId !== "REPLACE_ME" &&
    !!c.authDomain && c.authDomain !== "REPLACE_ME" &&
    !!c.storageBucket && c.storageBucket !== "REPLACE_ME" &&
    !!c.apiKey && /^AIza[A-Za-z0-9_-]{10,}$/.test(c.apiKey) &&
    !!c.messagingSenderId && /^\d+$/.test(c.messagingSenderId) &&
    !!c.appId && c.appId.indexOf(":") !== -1 && c.appId !== "REPLACE_ME";
}
var FIREBASE_CONFIG;
if (isDevEnvironment() && devFirebaseConfigIsReal()){
  FIREBASE_CONFIG = FIREBASE_CONFIG_DEV;
} else {
  FIREBASE_CONFIG = FIREBASE_CONFIG_PROD;
  if (isDevEnvironment()) console.warn("watkins-service-orders-dev config missing or malformed -- falling back to the production Firebase config. This should not happen once the real dev config is set; check FIREBASE_CONFIG_DEV in js/core.js.");
}
var fdb = null;
/* fauth (Firebase Authentication) is the ONLY gate on privileged actions
   app-wide -- there is no PIN left anywhere in this app (see Auth Phase 5
   in docs/AUTH_DESIGN.md). Requires the "Email/Password" sign-in provider
   to be enabled for this project in the Firebase Console (Authentication
   > Sign-in method) -- a manual one-time step, same pattern as
   firestore.rules needing a manual publish; nothing here enables it
   automatically. fauth stays null (same graceful-degrade pattern as fdb)
   if the SDK didn't load or the project isn't set up for it yet -- login
   UI simply won't work until then, nothing else in the app is affected. */
var fauth = null;
try{
  if (window.firebase && firebase.initializeApp){
    firebase.initializeApp(FIREBASE_CONFIG);
    fdb = firebase.firestore();
    if (firebase.auth) fauth = firebase.auth();
  }
}catch(e){ fdb = null; fauth = null; }
var cloudIndexCache = [];
/* CompanyCam link state for the work order currently being edited. Moved
   here from js/workorders.js (2026-07-11, real bug fix): js/companycam.js
   loads BEFORE js/workorders.js in index.html's script order but also
   references these vars, which only worked by accident of which script
   happened to finish loading first -- on a cold/uncached load it's a real
   race, and it broke for real on production's very first page load (a
   ReferenceError thrown from inside the auth-state-change handler, since
   recomputeIsAdmin() now calls updateAdminUI() -> renderCCLinkInfo() much
   earlier in the page lifecycle than before Auth Phase 5). core.js always
   loads first, so declaring shared state actually used across modules here
   (matching every other core.js global) makes this correct regardless of
   which order the rest of the modules happen to load in. */
var ccLinkedProjectId = null;
var ccLinkedProjectName = "";
/* STABLE BUILDING IDENTITY for the work order currently open in the form
   (audit FIX 1). Set by fill() from the loaded doc's stored buildingId/
   customerId, by bpSelectBuilding() when a building is picked, and by
   saveOrder() from ensureCustomerAndBuilding()'s result. null = no stable
   id known yet (a brand-new or legacy order) — readers fall back to the
   name-derived slug via currentWorkOrderBuildingId(). Declared here (not
   js/workorders.js) for the same load-order reason as ccLinkedProjectId
   above. Once set, renaming/typo-ing the job name can no longer fork a
   new building — history, base map, and the CompanyCam link stay bound
   to this id. */
var currentBuildingId = null;
var currentCustomerId = null;
/* The CompanyCam DOCUMENT artifact for the work order currently open — the
   uploaded PDF's id + content hash (uploadPdfToCompanyCam /
   ccPersistDocumentInfo, js/history.js). Same load-order home as the
   identities above. These used to live only on the Firestore doc and the
   in-memory `o` of the session that uploaded — collect() rebuilt orders
   WITHOUT them, so a reopened order forgot its own uploaded artifact: the
   #54 idempotency guard didn't survive a reload, and status reconciliation
   couldn't see that a document already existed (Sophia's Curb Flashing
   false "failed", Job 17476). fill() adopts them, collect() stamps them
   back, uploads update them. */
var currentCcDocumentId = null;
var currentCcDocumentHash = null;

/* ================= Account / login =================
   Reachable via the header's "🔐 Account" button. Role/permission display
   below reads straight off the signed-in user's ID token
   (getIdTokenResult().claims), NOT a Firestore read -- the token already
   carries { owner, role, mfaOk } once signed in (see "Custom claims size"
   in docs/AUTH_DESIGN.md for why claims stay this small). currentAuthClaims
   drives isAdmin (see recomputeIsAdmin() below) and every privileged
   control's visibility app-wide -- real gating, not just display. */
var currentAuthUser = null;
var currentAuthClaims = null;
if (fauth){
  fauth.onAuthStateChanged(function(user){
    currentAuthUser = user;
    if (user){
      user.getIdTokenResult().then(function(res){
        currentAuthClaims = res.claims;
        recomputeIsAdmin();
        updateAccountUI();
        renderLoginGate();
      }).catch(function(){ currentAuthClaims = null; recomputeIsAdmin(); updateAccountUI(); renderLoginGate(); });
    } else {
      currentAuthClaims = null;
      recomputeIsAdmin();
      updateAccountUI();
      renderLoginGate();
    }
  });
  checkAuthBootstrapStatus();
}
function updateAccountUI(){
  var btn = document.getElementById("account-toggle");
  if (!btn) return;
  /* innerHTML (not textContent) -- preserves the icon + .tab-label span
     structure the mobile header CSS relies on for icon-only display; see
     the matching note on updateAdminUI() and "Mobile header/toolbar pass"
     in DEV_NOTES.md. esc() escapes the email since it's user-supplied data
     going into innerHTML. */
  btn.innerHTML = '🔐<span class="tab-label"> ' + esc(currentAuthUser ? (currentAuthUser.email || "Account") : "Account") + '</span>';
  if (document.getElementById("account-modal").style.display !== "none") renderAccountModal();
}
function openAccountModal(){
  document.getElementById("account-modal").style.display = "";
  lockBodyScroll();
  renderAccountModal();
}
function closeAccountModal(){
  document.getElementById("account-modal").style.display = "none";
  unlockBodyScroll();
}
function renderAccountModal(){
  var host = document.getElementById("account-modal-body");
  if (!host) return;
  if (!fauth){
    host.innerHTML = '<p class="hint">Sign-in isn\'t available right now (Firebase Auth didn\'t load, or the ' +
      'Email/Password sign-in provider isn\'t enabled for this project yet).</p>';
    return;
  }
  if (currentAuthUser){
    var roleLine = currentAuthClaims && currentAuthClaims.role ?
      ' — role: <b>' + esc(currentAuthClaims.role) + '</b>' + (currentAuthClaims.owner ? ' (owner)' : '') :
      ' — no role assigned yet';
    var manageUsersBtn = (currentAuthClaims && (currentAuthClaims.owner === true || currentAuthClaims.role === "admin")) ?
      '<button class="btn" onclick="openUserManagementModal()">Manage Users</button>' : '';
    host.innerHTML =
      '<p class="hint" style="margin:0 0 10px">Signed in as <b>' + esc(currentAuthUser.email || "") + '</b>' + roleLine + '</p>' +
      '<div class="btnrow">' + manageUsersBtn + '<button class="btn danger" onclick="signOutUser()">Sign Out</button></div>';
  } else {
    host.innerHTML =
      '<div class="fld"><label>Email</label><input type="email" id="login-email" autocomplete="username"></div>' +
      '<div class="fld"><label>Password</label><input type="password" id="login-password" autocomplete="current-password"></div>' +
      '<div class="btnrow"><button class="btn primary" onclick="signInWithEmail()">Sign In</button>' +
      '<button class="btn" onclick="sendPasswordReset()">Forgot Password?</button></div>';
  }
}
async function signInWithEmail(){
  if (!fauth) return;
  var email = val("login-email").trim();
  var password = val("login-password");
  if (!email || !password){ toast("Enter email and password."); return; }
  toast("Signing in…");
  try{
    await fauth.signInWithEmailAndPassword(email, password);
    toast("Signed in ✓");
  }catch(e){ toast("Sign-in failed: " + e.message); }
}
async function signOutUser(){
  if (!fauth) return;
  try{
    await fauth.signOut();
    toast("Signed out");
  }catch(e){ toast("Sign-out failed: " + e.message); }
}
/* Without actionCodeSettings, Firebase's password-reset email lands the
   user on Firebase's own hosted page with no way back to the app at all --
   Mark's exact complaint about the crew-invite flow. `url` here is the
   "Continue" link shown after the reset completes; window.location.origin
   is already environment-aware for free (resolves to whichever
   dev/production URL the app is actually running on, no extra config
   needed) -- same principle as isDevEnvironment() above, just via the
   browser's own location instead of a hostname string match. */
function passwordResetActionCodeSettings(){
  return { url: window.location.origin + "/" };
}
async function sendPasswordReset(){
  if (!fauth) return;
  var email = val("login-email").trim();
  if (!email){ toast("Enter your email first."); return; }
  try{
    await fauth.sendPasswordResetEmail(email, passwordResetActionCodeSettings());
    toast("Password reset email sent (if that account exists) ✓");
  }catch(e){ toast("Couldn't send reset email: " + e.message); }
}

/* ================= User Management (Auth Phase 5) =================
   See docs/AUTH_DESIGN.md. Lets an owner/admin invite crew accounts and
   assign roles without touching Firebase Console directly. Client-side
   visibility (the "Manage Users" button, this modal) is convenience only --
   every real check happens server-side (create_user/assign_role in
   netlify/functions/auth.js) and at the rules layer (users/{uid} is
   write:false for every client, no exceptions), so a field_tech who
   somehow opened this modal anyway still can't do anything through it. */
async function openUserManagementModal(){
  document.getElementById("usermgmt-modal").style.display = "";
  lockBodyScroll();
  await renderUserManagementModal();
}
function closeUserManagementModal(){
  document.getElementById("usermgmt-modal").style.display = "none";
  unlockBodyScroll();
}
async function renderUserManagementModal(){
  var host = document.getElementById("usermgmt-modal-body");
  if (!host || !fdb) return;
  host.innerHTML = '<p class="hint">Loading…</p>';
  var roles = [], users = [];
  try{
    var rolesSnap = await fdb.collection("roles").get();
    rolesSnap.forEach(function(d){ roles.push(d.data()); });
    roles.sort(function(a,b){ return (b.rank||0) - (a.rank||0); });
    var usersSnap = await fdb.collection("users").get();
    usersSnap.forEach(function(d){ users.push(d.data()); });
    users.sort(function(a,b){ return (a.email||"").localeCompare(b.email||""); });
  }catch(e){
    host.innerHTML = '<p class="hint">Couldn\'t load users/roles: ' + esc(e.message) + '</p>';
    return;
  }
  var isOwner = !!(currentAuthClaims && currentAuthClaims.owner === true);
  // Owner can invite into any role except "owner" itself (unique, set only
  // via bootstrap/transfer). A non-owner admin can only invite non-admin
  // roles -- matches create_user's own server-side hierarchy check exactly,
  // so the dropdown never offers an option the server would reject anyway.
  var inviteRoleOptions = roles.filter(function(r){
    if (r.id === "owner") return false;
    if (r.id === "admin" && !isOwner) return false;
    return true;
  }).map(function(r){ return '<option value="' + esc(r.id) + '">' + esc(r.label || r.id) + '</option>'; }).join("");

  var rows = users.map(function(u){
    var isSelf = currentAuthUser && u.uid === currentAuthUser.uid;
    var isOwnerRow = u.role === "owner";
    var roleOptions = roles.filter(function(r){
      if (r.id === "owner") return false; // owner role changes go through transfer_owner, not this control
      if (r.id === "admin" && !isOwner) return false; // matches assign_role's involvesAdmin -> owner-only rule
      return true;
    }).map(function(r){
      return '<option value="' + esc(r.id) + '"' + (r.id === u.role ? " selected" : "") + '>' + esc(r.label || r.id) + '</option>';
    }).join("");
    var disabledReason = isSelf ? "You can't change your own role" : (isOwnerRow ? "Transfer ownership to change the owner" : "");
    var status = u.status || "active";
    var isDeleted = status === "deleted";
    // Deleted is a permanent, terminal state -- no actions offered at all
    // once reached, matching audit_logs' own "no further changes, ever"
    // spirit. The row still renders (email/role/status visible) so
    // historical attribution stays legible, just with nothing left to do.
    var actionButtons = "";
    if (!isSelf && !isOwnerRow && !isDeleted){
      actionButtons =
        '<button class="btn" onclick="saveUserRole(\'' + esc(u.uid) + '\')">Save</button> ' +
        '<button class="btn" onclick="resendInvite(\'' + esc(u.uid) + '\')" title="Re-send the set-password email">Resend invite</button> ' +
        (status === "disabled" ?
          '<button class="btn" onclick="enableUser(\'' + esc(u.uid) + '\')">Re-enable</button>' :
          '<button class="btn danger" onclick="disableUser(\'' + esc(u.uid) + '\', \'' + esc(u.email || "") + '\')">Disable</button>') +
        (isOwner ?
          ' <button class="btn danger" onclick="deleteUserPermanently(\'' + esc(u.uid) + '\', \'' + esc(u.email || "") + '\')" title="Permanent -- owner only">Delete…</button>' : '');
    }
    return '<tr' + (isDeleted ? ' style="opacity:.55"' : '') + '>' +
      '<td style="padding:6px 8px">' + esc(u.email || "") + (isSelf ? ' <span class="hint">(you)</span>' : '') + '</td>' +
      '<td style="padding:6px 8px">' +
        (isSelf || isOwnerRow || isDeleted ?
          '<span class="hint" title="' + esc(disabledReason) + '">' + esc(u.role || "") + '</span>' :
          '<select id="role-select-' + esc(u.uid) + '">' + roleOptions + '</select>') +
      '</td>' +
      '<td style="padding:6px 8px">' + esc(status) + '</td>' +
      '<td style="padding:6px 8px;white-space:nowrap">' + actionButtons + '</td>' +
    '</tr>';
  }).join("");

  host.innerHTML =
    '<p class="hint" style="margin:0 0 10px">Invite a new user — they get an email to set their own password. ' +
    'No one ever types or sees another person\'s password here.</p>' +
    '<div class="fld"><label>Email</label><input type="email" id="invite-email"></div>' +
    '<div class="fld"><label>Display Name (optional)</label><input type="text" id="invite-name"></div>' +
    '<div class="fld"><label>Role</label><select id="invite-role">' + inviteRoleOptions + '</select></div>' +
    '<div class="btnrow"><button class="btn primary" onclick="inviteUser()">Invite User</button></div>' +
    '<h3 style="margin:18px 0 8px">Existing Users</h3>' +
    '<table style="width:100%;border-collapse:collapse;font-size:13px">' +
      '<thead><tr style="text-align:left;border-bottom:1px solid #ddd">' +
        '<th style="padding:6px 8px">Email</th><th style="padding:6px 8px">Role</th>' +
        '<th style="padding:6px 8px">Status</th><th style="padding:6px 8px"></th>' +
      '</tr></thead>' +
      '<tbody>' + (rows || '<tr><td colspan="4" style="padding:8px" class="hint">No users yet.</td></tr>') + '</tbody>' +
    '</table>';
}
/* Real incident, fixed here (see auth.js's create_user/sendInviteEmail for
   the full story): this used to call the client SDK's
   fauth.sendPasswordResetEmail() wrapped in a bare try/catch, which
   silently swallowed the failure and told the inviting admin "email sent"
   regardless of whether it actually was -- no crew member ever received an
   invite and nobody knew. The server now sends the real email itself (via
   Resend, same delivery path work-order emails already use) and reports
   back honestly whether it worked -- this toast reflects that truthfully,
   including telling the admin to use Resend Invite if the send failed but
   the account was still created (a real, recoverable state, not a dead
   end). appUrl is this browser's own origin -- same environment-aware
   principle as passwordResetActionCodeSettings(), just sent to the server
   since the invite link (a 7-day custom token as of 2026-07-16 -- see the
   invite-token comment block in netlify/functions/auth.js, and the
   ?invite= handling at pendingInviteToken above) is generated
   server-side. */
async function inviteUser(){
  var email = val("invite-email").trim();
  var displayName = val("invite-name").trim();
  var roleId = document.getElementById("invite-role") ? document.getElementById("invite-role").value : "";
  if (!email || !roleId){ toast("Enter an email and pick a role."); return; }
  toast("Creating account…");
  try{
    var r = await fetch("/.netlify/functions/auth", {
      method: "POST", headers: await authHeaders(),
      body: JSON.stringify({ action: "create_user", email: email, roleId: roleId, displayName: displayName, appUrl: window.location.origin })
    });
    var out = await r.json().catch(function(){ return null; });
    if (!r.ok || !out || !out.ok) throw new Error((out && out.error) || ("server error " + r.status));
    if (out.emailSent){
      toast("Account created ✓ — invite email sent to " + email);
    } else {
      toast("Account created, but the invite EMAIL FAILED to send (" + (out.emailError || "unknown error") +
        "). The account exists -- use Resend Invite once the problem's fixed, don't create it again.");
    }
    await renderUserManagementModal();
  }catch(e){ toast("Couldn't create account: " + e.message); }
}
async function resendInvite(uid){
  toast("Resending invite…");
  try{
    var r = await fetch("/.netlify/functions/auth", {
      method: "POST", headers: await authHeaders(),
      body: JSON.stringify({ action: "resend_invite", targetUid: uid, appUrl: window.location.origin })
    });
    var out = await r.json().catch(function(){ return null; });
    if (!r.ok || !out || !out.ok) throw new Error((out && out.error) || ("server error " + r.status));
    toast("Invite email re-sent ✓");
  }catch(e){ toast("Couldn't resend invite: " + e.message); }
}
/* Disable is the primary removal action (see docs/AUTH_DESIGN.md) --
   revokes access immediately without touching any historical
   attribution. Confirm text names the actual consequence, not just
   "are you sure." */
async function disableUser(uid, email){
  if (!confirm("Disable " + email + "'s account? They won't be able to sign in until re-enabled. Their name stays on their existing work orders/findings/photos/audit entries.")) return;
  toast("Disabling…");
  try{
    var r = await fetch("/.netlify/functions/auth", {
      method: "POST", headers: await authHeaders(),
      body: JSON.stringify({ action: "disable_user", targetUid: uid })
    });
    var out = await r.json().catch(function(){ return null; });
    if (!r.ok || !out || !out.ok) throw new Error((out && out.error) || ("server error " + r.status));
    toast("Account disabled ✓");
    await renderUserManagementModal();
  }catch(e){ toast("Couldn't disable account: " + e.message); }
}
async function enableUser(uid){
  toast("Re-enabling…");
  try{
    var r = await fetch("/.netlify/functions/auth", {
      method: "POST", headers: await authHeaders(),
      body: JSON.stringify({ action: "enable_user", targetUid: uid })
    });
    var out = await r.json().catch(function(){ return null; });
    if (!r.ok || !out || !out.ok) throw new Error((out && out.error) || ("server error " + r.status));
    toast("Account re-enabled ✓");
    await renderUserManagementModal();
  }catch(e){ toast("Couldn't re-enable account: " + e.message); }
}
/* Owner-only, deliberately harder to reach than Disable (a second,
   separate confirm naming the PERMANENT consequence, not the same one-line
   confirm as disable). The Firebase Auth account is gone forever; the
   users/{uid} Firestore record is kept (archived) specifically so past
   work orders/findings/photos/audit entries still show a real name instead
   of an orphaned id -- explained in the confirm text so this is never
   mistaken for "erases their history too." */
async function deleteUserPermanently(uid, email){
  if (!confirm("PERMANENTLY delete " + email + "'s account?\n\nThis cannot be undone -- they will never be able to sign in again with this account. Their name will still appear on their existing work orders/findings/photos/audit entries (that history is kept), but the login itself is gone forever.\n\nIf you just want to revoke access and might restore it later, use Disable instead.")) return;
  if (!confirm("Really permanently delete " + email + "? This is the second and final confirmation.")) return;
  toast("Deleting…");
  try{
    var r = await fetch("/.netlify/functions/auth", {
      method: "POST", headers: await authHeaders(),
      body: JSON.stringify({ action: "delete_user", targetUid: uid })
    });
    var out = await r.json().catch(function(){ return null; });
    if (!r.ok || !out || !out.ok) throw new Error((out && out.error) || ("server error " + r.status));
    toast("Account permanently deleted");
    await renderUserManagementModal();
  }catch(e){ toast("Couldn't delete account: " + e.message); }
}
async function saveUserRole(uid){
  var sel = document.getElementById("role-select-" + uid);
  if (!sel) return;
  var roleId = sel.value;
  toast("Updating role…");
  try{
    var r = await fetch("/.netlify/functions/auth", {
      method: "POST", headers: await authHeaders(),
      body: JSON.stringify({ action: "assign_role", targetUid: uid, roleId: roleId })
    });
    var out = await r.json().catch(function(){ return null; });
    if (!r.ok || !out || !out.ok) throw new Error((out && out.error) || ("server error " + r.status));
    toast("Role updated ✓");
    await renderUserManagementModal();
  }catch(e){ toast("Couldn't update role: " + e.message); }
}

/* ================= Require-login gate (Auth Phase 5, dev only) =================
   See docs/AUTH_DESIGN.md's "Phase 5" section. Blocks the whole app behind
   #login-gate until someone is signed in -- UNLESS fauth itself isn't
   configured/available (Email/Password provider not enabled yet, SDK
   didn't load, etc.), in which case this fails OPEN rather than locking
   everyone out over an environment gap, matching fdb/fauth's existing
   null-safe degrade pattern everywhere else in this file. Dev branch only
   by construction (this code doesn't exist on main) -- zero risk to
   production, which is a completely separate deployment.

   authBootstrapStatus: null while unchecked/checking (gate stays hidden,
   never flashes a false "locked out" state before the read completes),
   true once app_settings/auth_bootstrap confirms an owner exists, false
   if it doesn't yet -- in which case the gate shows the one-time owner
   setup form instead of a plain sign-in form. Fails OPEN (treated as
   "bootstrapped") on a read error too -- a transient Firestore hiccup
   should never be able to brick the entire app for everyone. */
var authBootstrapStatus = null;
/* Custom invite links (?invite=<token> -- see the invite-token comment
   block in netlify/functions/auth.js for the whole design: 7-day expiry,
   single-use, hashed at rest, replacing Firebase's ~1-hour password-reset
   links that kept dying in crew inboxes). When a token is present and
   nobody's signed in, the login gate renders a set-your-password form
   instead of the sign-in form, and on success signs the new user straight
   in with the password they just chose -- no retyping, no bouncing
   through Firebase's hosted pages. If someone's ALREADY signed in the
   param is simply ignored (renderLoginGate() hides the gate entirely for
   a signed-in user) -- an admin clicking their own test invite shouldn't
   get logged out. */
var pendingInviteToken = null;
try { pendingInviteToken = new URLSearchParams(window.location.search).get("invite") || null; } catch(e){ /* ancient browser: invite links just fall back to normal sign-in */ }
function clearPendingInvite(){
  pendingInviteToken = null;
  /* Drop ?invite= from the address bar so a refresh (or a bookmark of the
     landed page) doesn't re-run a burned token through the gate. */
  try { history.replaceState(null, "", window.location.pathname); } catch(e){}
}
async function checkAuthBootstrapStatus(){
  if (!fdb){ authBootstrapStatus = true; renderLoginGate(); return; }
  try{
    var snap = await fdb.collection("app_settings").doc("auth_bootstrap").get();
    authBootstrapStatus = !!(snap.exists && snap.data().ownerBootstrapped === true);
  }catch(e){ authBootstrapStatus = true; }
  renderLoginGate();
}
/* Idempotent login-gate scroll lock (prod hotfix 27bacb9): the gate holds AT
   MOST one lock, released the instant it hides. Without this, the signed-in
   hide path (onAuthStateChanged -> renderLoginGate() with currentAuthUser set)
   early-returned without unlocking, so body{overflow:hidden} stayed on after a
   fresh login and froze the WO/leak form. Pairs with the ref-counted
   lockBodyScroll/unlockBodyScroll below. */
var loginGateScrollLocked = false;
function setLoginGateScrollLock(on){
  if (on === loginGateScrollLocked) return;
  loginGateScrollLocked = on;
  if (on) lockBodyScroll(); else unlockBodyScroll();
}
function renderLoginGate(){
  var gate = document.getElementById("login-gate");
  if (!gate) return;
  if (!fauth || authBootstrapStatus === null || currentAuthUser){
    gate.style.display = "none";
    setLoginGateScrollLock(false);
    return;
  }
  gate.style.display = "";
  setLoginGateScrollLock(true);
  var host = document.getElementById("login-gate-body");
  if (!host) return;
  if (!authBootstrapStatus){
    host.innerHTML = loginGateBootstrapHtml();
  } else if (pendingInviteToken){
    host.innerHTML = loginGateAcceptInviteHtml();
    checkPendingInvite(); // async on purpose -- greet/fail-fast fills in when the server answers
  } else {
    host.innerHTML = loginGateSignInHtml();
  }
}
/* This screen is the one door into the app -- a failure here (wrong
   secret, weak password, a misconfigured env var) MUST be impossible to
   miss. The app's normal toast() auto-hides after 3.5s, which is exactly
   the kind of gap that made a real failure here look like "the button
   does nothing" (confirmed live: the request WAS failing correctly with a
   clear server error, but by the time anyone looked back at the screen
   the toast had already vanished). setLoginGateStatus() writes into a
   persistent line INSIDE the form that stays up until the next attempt or
   success -- never auto-dismisses. toast() is still called too, for
   consistency with the rest of the app, but it is never the only signal
   on this screen. */
function setLoginGateStatus(msg, isError){
  var el = document.getElementById("login-gate-status");
  if (!el) return;
  el.textContent = msg;
  el.style.display = msg ? "block" : "none";
  el.style.color = isError ? "#b4223f" : "#2e7d32";
  el.style.fontWeight = "600";
  el.style.margin = "10px 0 0";
}
function loginGateSignInHtml(){
  return '<div class="fld"><label>Email</label><input type="email" id="gate-email" autocomplete="username"></div>' +
    '<div class="fld"><label>Password</label><input type="password" id="gate-password" autocomplete="current-password"></div>' +
    '<div class="btnrow"><button class="btn primary" onclick="gateSignIn()">Sign In</button>' +
    '<button class="btn" onclick="gateForgotPassword()">Forgot Password?</button></div>' +
    '<p id="login-gate-status" style="display:none"></p>';
}
function loginGateBootstrapHtml(){
  return '<p class="hint" style="margin:0 0 10px">No owner account exists yet. Complete this one-time setup ' +
    'with your OWN email and password, plus the bootstrap secret configured in Netlify — this runs exactly once, ever.</p>' +
    '<div class="fld"><label>Owner Email</label><input type="email" id="bootstrap-email" value="marks@watkinsroofing.net"></div>' +
    '<div class="fld"><label>Password</label><input type="password" id="bootstrap-password" autocomplete="new-password"></div>' +
    '<div class="fld"><label>Confirm Password</label><input type="password" id="bootstrap-password2" autocomplete="new-password"></div>' +
    '<div class="fld"><label>Bootstrap Secret</label><input type="password" id="bootstrap-secret" autocomplete="off"></div>' +
    '<div class="btnrow"><button class="btn primary" onclick="runOwnerBootstrap()">Create Owner Account</button></div>' +
    '<p id="login-gate-status" style="display:none"></p>';
}
async function gateSignIn(){
  var email = val("gate-email").trim();
  var password = val("gate-password");
  if (!email || !password){ setLoginGateStatus("Enter email and password.", true); return; }
  setLoginGateStatus("Signing in…", false);
  try{ await fauth.signInWithEmailAndPassword(email, password); setLoginGateStatus("Signed in ✓", false); }
  catch(e){ setLoginGateStatus("Sign-in failed: " + e.message, true); }
}
async function gateForgotPassword(){
  var email = val("gate-email").trim();
  if (!email){ setLoginGateStatus("Enter your email first.", true); return; }
  try{
    await fauth.sendPasswordResetEmail(email, passwordResetActionCodeSettings());
    setLoginGateStatus("Password reset email sent (if that account exists) ✓", false);
  }catch(e){ setLoginGateStatus("Couldn't send reset email: " + e.message, true); }
}
/* ---- Accept-invite mode (see pendingInviteToken above) ---- */
function loginGateAcceptInviteHtml(){
  return '<p class="hint" style="margin:0 0 4px">Welcome to RoofOps! Choose a password to finish setting up your account.</p>' +
    '<p id="invite-email-line" class="hint" style="display:none;font-weight:600;margin:0 0 10px"></p>' +
    '<div class="fld"><label>New Password (at least 8 characters)</label><input type="password" id="invite-password" autocomplete="new-password"></div>' +
    '<div class="fld"><label>Confirm Password</label><input type="password" id="invite-password2" autocomplete="new-password"></div>' +
    '<div class="btnrow"><button class="btn primary" id="invite-accept-btn" onclick="gateAcceptInvite()">Set Password &amp; Sign In</button>' +
    '<button class="btn" onclick="dismissInviteMode()">Back to Sign In</button></div>' +
    '<p id="login-gate-status" style="display:none"></p>';
}
function dismissInviteMode(){
  clearPendingInvite();
  renderLoginGate();
}
/* Greets the recipient by the email the invite is for, and -- the part
   that actually matters in the field -- fails FAST on a dead link: the
   old Firebase flow let you click through to a hosted page, and only
   told you the link was dead after the fact. Here the form disables
   itself with the one message that says what to do next, before anyone
   has typed a password twice. */
async function checkPendingInvite(){
  var token = pendingInviteToken;
  try{
    var r = await fetch("/.netlify/functions/auth", {
      method: "POST", headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ action: "check_invite", token: token })
    });
    var out = await r.json().catch(function(){ return null; });
    /* Stale response guard: the user may have tapped "Back to Sign In"
       (or accepted) while this was in flight -- never write into a form
       that's no longer the invite form. */
    if (pendingInviteToken !== token) return;
    if (!r.ok || !out || !out.ok) throw new Error((out && out.error) || ("server error " + r.status));
    var line = document.getElementById("invite-email-line");
    if (line){ line.textContent = "Setting up: " + out.email; line.style.display = "block"; }
  }catch(e){
    if (pendingInviteToken !== token) return;
    var btn = document.getElementById("invite-accept-btn");
    if (btn) btn.disabled = true;
    setLoginGateStatus(e.message, true);
  }
}
async function gateAcceptInvite(){
  var p1 = val("invite-password");
  var p2 = val("invite-password2");
  if (p1.length < 8){ setLoginGateStatus("Password must be at least 8 characters.", true); return; }
  if (p1 !== p2){ setLoginGateStatus("Passwords don't match.", true); return; }
  setLoginGateStatus("Setting your password…", false);
  try{
    var r = await fetch("/.netlify/functions/auth", {
      method: "POST", headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ action: "accept_invite", token: pendingInviteToken, password: p1 })
    });
    var out = await r.json().catch(function(){ return null; });
    if (!r.ok || !out || !out.ok) throw new Error((out && out.error) || ("server error " + r.status));
    /* Token is burned server-side the moment the password is set -- clear
       it locally BEFORE signing in so nothing ever retries it. */
    clearPendingInvite();
    setLoginGateStatus("Password set ✓ — signing you in…", false);
    await fauth.signInWithEmailAndPassword(out.email, p1);
    /* onAuthStateChanged hides the gate from here. */
  }catch(e){ setLoginGateStatus(e.message, true); }
}
/* One-time owner bootstrap -- creates the owner account, signs into it in
   THIS browser, force-refreshes the ID token (claims were just set by the
   Admin SDK moments ago; a token minted before that could still reflect
   the old, claims-less state), then seeds the 9 approved roles using that
   fresh owner token. All three steps or none -- if role-seeding fails
   after a successful account creation, the status line says so explicitly
   rather than silently leaving roles unseeded. Uses the signed-in
   credential's own token directly for the seed_roles call rather than
   authHeaders()/currentAuthUser, since onAuthStateChanged's listener
   updating those module-level vars is not guaranteed to have already run
   by the time signInWithEmailAndPassword's own promise resolves. */
async function runOwnerBootstrap(){
  var email = val("bootstrap-email").trim();
  var password = val("bootstrap-password");
  var password2 = val("bootstrap-password2");
  var secret = val("bootstrap-secret");
  if (!email || !password || !secret){ setLoginGateStatus("Fill in every field.", true); return; }
  if (password !== password2){ setLoginGateStatus("Passwords don't match.", true); return; }
  if (password.length < 8){ setLoginGateStatus("Password must be at least 8 characters.", true); return; }
  setLoginGateStatus("Creating owner account…", false);
  try{
    var r = await fetch("/.netlify/functions/auth", {
      method: "POST", headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ action: "bootstrap_owner", email: email, password: password, secret: secret })
    });
    var out = await r.json().catch(function(){ return null; });
    if (!r.ok || !out || !out.ok) throw new Error((out && out.error) || ("server error " + r.status));

    setLoginGateStatus("Owner account created — signing in…", false);
    var cred = await fauth.signInWithEmailAndPassword(email, password);
    var token = await cred.user.getIdToken(true);

    setLoginGateStatus("Seeding roles…", false);
    var r2 = await fetch("/.netlify/functions/auth", {
      method: "POST", headers: { "Content-Type": "application/json", "Authorization": "Bearer " + token },
      body: JSON.stringify({ action: "seed_roles" })
    });
    var out2 = await r2.json().catch(function(){ return null; });
    if (!r2.ok || !out2 || !out2.ok) {
      throw new Error((out2 && out2.error) || "Role seeding failed — the owner account and sign-in both worked; re-open Account and try again, or ask an admin to re-run seed_roles.");
    }
    setLoginGateStatus("Owner account ready ✓ — " + out2.seeded.length + " roles seeded.", false);
    authBootstrapStatus = true;
    renderLoginGate();
  }catch(e){ setLoginGateStatus("Setup failed: " + e.message, true); }
}

/* Client-side wrappers around netlify/functions/photos.js -- the ONLY
   place this app is allowed to touch Firebase Storage. Mark's explicit
   architecture decision: Storage security rules stay deny-all (an open
   bucket would make every customer's roof photos world-readable to anyone
   who guessed a URL) -- the client therefore never talks to Storage
   directly, only through this server-side proxy (Admin SDK,
   service-account credentials, not subject to Storage rules). The bucket
   itself stays completely sealed to the browser. See "Photo storage
   migration" in DEV_NOTES.md.

   EVERY call below goes through authHeaders(), which attaches the signed-in
   user's Firebase ID token as `Authorization: Bearer <token>`. As of
   2026-07-13 photos.js REQUIRES that token on every action (upload, get,
   get_batch, delete) and 401s without it -- previously these four were
   reachable by anyone on the internet with no token at all, including
   `delete`. authHeaders() calls getIdToken(), which transparently refreshes
   an expired token (Firebase ID tokens last ~1hr, and a tech's tab is open
   all day), so it must never be replaced with a token cached in a variable.

   This is an AUTHENTICATION gate, not a permission gate: any signed-in
   Watkins user passes, so a tech keeps FULL view/upload/delete on their own
   work orders and photos -- fixing your own mistake in the field is a
   supported operation, not a privileged one. */
async function uploadPhotoToStorage(workOrderId, photoIndex, dataUrl){
  var r = await fetch("/.netlify/functions/photos", {
    method: "POST", headers: await authHeaders(),
    body: JSON.stringify({ action: "upload", workOrderId: workOrderId, photoIndex: photoIndex, dataUrl: dataUrl })
  });
  var out = null;
  try{ out = await r.json(); }catch(e){}
  if (!r.ok || !out || !out.ok) throw new Error((out && out.error) || ("upload failed: server error " + r.status));
  return out.storageRef;
}
async function deletePhotoFromStorage(workOrderId, photoIndex){
  try{
    var r = await fetch("/.netlify/functions/photos", {
      method: "POST", headers: await authHeaders(),
      body: JSON.stringify({ action: "delete", workOrderId: workOrderId, photoIndex: photoIndex })
    });
    await r.json().catch(function(){});
  }catch(e){ console.warn("photo delete from storage failed (non-fatal — orphaned Storage object, no user-visible impact)", e); }
}
async function fetchPhotoFromStorage(workOrderId, photoIndex){
  var r = await fetch("/.netlify/functions/photos", {
    method: "POST", headers: await authHeaders(),
    body: JSON.stringify({ action: "get", workOrderId: workOrderId, photoIndex: photoIndex })
  });
  var out = null;
  try{ out = await r.json(); }catch(e){}
  if (!r.ok || !out || !out.ok) throw new Error((out && out.error) || ("couldn't load photo: server error " + r.status));
  return out.dataUrl;
}
/* Resolves ONE photo's full-resolution image, fetching from Storage on
   demand if it isn't already in memory -- returns the data URI, or null
   if there's genuinely nothing to show (no cached img, no storageRef: an
   incomplete/corrupt record). Caches the result onto p.img in memory only
   (never written back to Firestore/localStorage) so repeated calls this
   session (gallery -> lightbox -> PDF) don't re-fetch the same photo.
   Parses workOrderId/photoIndex back out of storageRef rather than
   assuming "whatever currentId is right now" -- correct regardless of
   which work order p actually belongs to. */
async function resolvePhotoImg(p){
  if (p.img) return p.img;
  /* Bytes may live ONLY in IndexedDB -- a locally-added photo not yet uploaded
     whose localStorage copy was offloaded to keep the ~5MB cache lean (Phase 1).
     Try the on-device IDB backup by localId first: it's the freshest local copy
     and needs no network. Closes the gap where resolvePhotoImg looked only in
     Storage, so an IDB-only photo couldn't be shown or exported. */
  if (p.localId){
    try{ var local = await idbGetPhoto(p.localId); if (local){ p.img = local; return local; } }catch(e){}
  }
  if (!p.storageRef) return null;
  var m = /^workorders\/([^/]+)\/(\d+)\.jpg$/.exec(p.storageRef);
  if (!m) return null;
  try{
    var dataUrl = await fetchPhotoFromStorage(m[1], +m[2]);
    p.img = dataUrl;
    return dataUrl;
  }catch(e){ return null; }
}
/* A photo slot with nothing to show, upload, or recover -- no img, no
   storageRef, no imgFallback/thumb, no localId. Dropped rather than
   re-persisted as an empty doc. Strict: any of those signals keeps it. */
function photoSlotIsEmpty(p){
  return !!p && !p.img && !p.storageRef && !p.imgFallback && !p.thumb && !p.localId;
}
/* The photo's Storage object index parsed out of its storageRef path
   (workorders/<id>/<index>.jpg). Storage paths are index-based, so this is how
   we tell which object a photo points at, independent of its array slot. */
function photoStorageIndex(p){
  var m = p && p.storageRef && /^workorders\/[^/]+\/(\d+)\.jpg$/.exec(p.storageRef);
  return m ? +m[1] : null;
}
async function cloudSaveOrder(o){
  if (!fdb) throw new Error("cloud not available");
  var main = {};
  Object.keys(o).forEach(function(k){ if (k !== "photos") main[k] = (o[k] == null ? "" : o[k]); });
  var ph = o.photos || [];
  /* Drop dead slots (photoSlotIsEmpty) rather than re-persist them; compact
     survivors to a contiguous 0..n-1. photoCount reflects the compacted set. */
  var writePhotos = ph.filter(function(p){ return !photoSlotIsEmpty(p); });
  var droppedEmpty = ph.length - writePhotos.length;
  main.photoCount = writePhotos.length;
  main.savedAt = Date.now();
  var ref = fdb.collection("workorders").doc(o.id);
  /* MULTI-DEVICE CLOBBER GUARD (optimistic concurrency). Refuse to overwrite a
     cloud doc that has advanced past the version THIS copy descends from
     (o._cloudBaseSavedAt, stamped at fetch). Without it, a stale copy
     auto-flushed from one device silently overwrote a newer save from another
     -- the PC<->phone tug-of-war that resurrected deleted photos and wiped
     re-adds. base 0 = a new/never-synced order -> not guarded (nothing to
     conflict with). A read failure here never blocks the save (best-effort).
     See "Multi-device clobber guard" in DEV_NOTES.md. */
  var base = o._cloudBaseSavedAt || 0;
  if (base){
    var cloudSavedAt = 0, gotCloud = false;
    try{ var curSnap = await ref.get(); cloudSavedAt = curSnap.exists ? (curSnap.data().savedAt || 0) : 0; gotCloud = true; }catch(e){}
    if (gotCloud && cloudSavedAt > base){
      var ce = new Error("This work order was updated on another device. Reopen it to get the latest version before saving — your changes on this screen weren't uploaded, so they don't overwrite the newer copy.");
      ce.__conflict = true;
      throw ce;
    }
  }
  await ref.set(main);
  /* Photos off base64/localStorage onto Storage (Mark's "photos gone in
     PDFs" bug, and the storage-is-full/pruning mess it grew out of -- see
     "Photo storage migration" in DEV_NOTES.md): a photo already carrying
     a storageRef and no raw .img was loaded from a previous save and
     never re-captured -- already in Storage, re-uploading identical bytes
     would be wasted work. Only a photo with real .img bytes right now
     (freshly captured/edited this session) gets uploaded. A failed
     upload does NOT abort the whole save -- findings/captions/pins still
     need to persist -- but is counted and surfaced as a thrown error
     after everything else commits, so saveOrder()'s existing
     never-silent cloud-error toast (see "Silent cloud-save failure" in
     DEV_NOTES.md) tells the tech to retry rather than the app quietly
     leaving a photo un-uploaded.

     CRITICAL DATA-LOSS GUARD, added after a real near-miss: a photo with
     NEITHER img NOR storageRef locally is the ONE dangerous case -- it
     means "write nothing for this photo," and if the in-memory record
     got here via a stripped/stale local cache (see
     orderPhotosAreStrippedLocally()) rather than a genuinely photo-less
     finding, blindly writing that would silently blank out real image
     data already sitting safely in the cloud. Before ever writing such a
     doc, check what's ALREADY there -- if the cloud already has real
     data at this exact photo, PRESERVE it instead of overwriting with
     nulls. This makes the destructive case structurally impossible at
     the one function every save path funnels through (saveOrder(),
     autosaves, ccImport's quiet save, the recover-unlogged-work-orders
     backfill -- all of them call this, not just the explicit Save
     button), rather than relying on every caller to have already fixed
     its own upstream data.

     Caught by testing, not just reasoned about: a photo WITH real .img
     whose UPLOAD ATTEMPT ITSELF FAILS (network blip, function down) is
     JUST AS DANGEROUS as one with no img at all -- both end up with
     nothing new and reliable to write. The guard below covers both:
     "no storageRef after this photo's upload attempt (whether none was
     ever tried, or one was tried and failed)" is the one condition that
     triggers a preserve-existing check, not just "no img provided." See
     "Save-time photo data-loss guard" in DEV_NOTES.md. */
  var uploadFailures = 0, preservedCount = 0, failedPhotoNums = [];
  var ops = [];
  /* Every Storage object index a surviving photo still points at after this
     save. Cleanup below is REFERENCE-AWARE -- it never deletes an object a
     photo still references -- instead of the old naive trailing index range,
     which destroyed a DIFFERENT photo's confirmed-good bytes on any
     remove/reorder (the live prod corruption fixed in the b0a57fe hotfix). */
  var referencedStorage = {};
  /* Re-home fetches must happen before any upload overwrites an index in the
     shared workorders/<id>/<n>.jpg namespace. Otherwise a swap like
     [A@0, B@1] -> [B, A] can upload B into index 0 before A has read its old
     bytes from index 0. Snapshot the bytes into p.img first; failed snapshots
     keep their old storageRef and are protected by referencedStorage below. */
  for (var ri = 0; ri < writePhotos.length; ri++){
    var rp = writePhotos[ri];
    var rpStorageRef = rp.storageRef || null;
    if (!rp.img && rpStorageRef && photoStorageIndex(rp) !== ri){
      try{ await resolvePhotoImg(rp); }
      catch(e){ console.warn("couldn't snapshot photo before storage realign (keeping existing ref)", e); }
    }
  }
  for (var i = 0; i < writePhotos.length; i++){
    var p = writePhotos[i];
    var storageRef = p.storageRef || null;
    var existingImg = null; // base64 backup already in Firestore -- carried forward as-is unless this save uploads a fresh replacement
    /* Trust the positional existing-doc lookup only when this save did NOT
       move photos: no dead slot dropped ahead of anything AND this photo's
       Storage object already sits at its slot index. Under a shift, doc p<i>
       may belong to a different photo, so its base64/storageRef must not be
       adopted here. */
    var positionStable = droppedEmpty === 0 && (!storageRef || photoStorageIndex(p) === i);
    if (p.img){
      try{ storageRef = await uploadPhotoToStorage(o.id, i, p.img); }
      catch(e){ uploadFailures++; failedPhotoNums.push(i + 1); console.warn("photo upload failed, will retry on next save", e); }
    } else if (storageRef && photoStorageIndex(p) !== i){
      /* A surviving photo whose Storage object sits at a different index than
         its new slot (a photo was removed/reordered ahead of it). The
         pre-pass above already tried to snapshot its bytes into p.img before
         any upload could overwrite the old index. If it is still img-less
         here, keep the old storageRef untouched -- cleanup is reference-aware,
         so the bytes are not deleted and the slots simply stay out of
         alignment until a later online save can re-home them. */
    }
    if ((!p.img || !storageRef) && positionStable){
      /* CRITICAL DATA-LOSS GUARD: on a stable save, a photo with neither fresh
         img nor a surviving storageRef is checked against what the cloud
         already holds, and real existing data is PRESERVED rather than
         overwritten with nulls. Runs only when positionStable so a shifted
         save can't cross-wire p<i> with a different photo's doc. */
      try{
        var existingSnap = await ref.collection("photos").doc("p" + i).get();
        if (existingSnap.exists){
          var existing = existingSnap.data();
          existingImg = existing.img || null;
          if (!storageRef && (existing.img || existing.storageRef)){
            storageRef = existing.storageRef || null;
            preservedCount++;
          }
        }
      }catch(e){ console.warn("couldn't check existing photo before save (proceeding without it — no data was overwritten)", e); }
    }
    if (storageRef){
      var refIdx = photoStorageIndex({ storageRef: storageRef });
      if (refIdx !== null) referencedStorage[refIdx] = true;
    }
    /* ccPhotoId  : set when this photo was IMPORTED FROM CompanyCam.
       ccFeedPhotoId: set when this photo was PUSHED TO CompanyCam's photo feed
       (see pushPhotosToCompanyCamFeed() in js/history.js). They are opposite
       directions and must not be confused.

       ccFeedPhotoId MUST be carried through this save. This .set() is a full
       overwrite, not a merge -- so omitting it here would silently erase the
       push record on the very next save of the work order, and the next
       send would re-push every photo and duplicate the whole set into the
       project feed. The flag IS the idempotency. */
    var photoDoc = {
      caption: p.caption || "", w: p.w || 0, h: p.h || 0, i: i,
      finding_id: p.finding_id || null, ccPhotoId: p.ccPhotoId || null, gps: p.gps || null,
      ccFeedPhotoId: p.ccFeedPhotoId || null,
      storageRef: storageRef, thumb: p.thumb || null
    };
    if (existingImg) photoDoc.img = existingImg;
    ops.push(ref.collection("photos").doc("p" + i).set(photoDoc));
  }
  /* Cleanup, ENUMERATED not count-bounded. Read what photo docs actually exist
     and delete any that aren't part of this save's compacted set
     (p0..p{writeCount-1}). The old cleanup deleted only up to the parent's
     photoCount field -- so once that field drifted below the real doc count
     (concurrent multi-device saves), "orphan" docs above it survived every
     save forever, including a delete-everything save (Mark's "delete all,
     still 4"). Storage is freed reference-awarely: an object a surviving photo
     still points at is never deleted, whatever index it lives at. */
  try{
    var existingDocs = await ref.collection("photos").get();
    existingDocs.forEach(function(d){
      var m = /^p(\d+)$/.exec(d.id);
      var docIdx = m ? +m[1] : null;
      if (!(docIdx !== null && docIdx < writePhotos.length)) ops.push(d.ref.delete());
      var data = d.data() || {};
      var sm = data.storageRef && /\/(\d+)\.jpg$/.exec(data.storageRef);
      var storageIdx = sm ? +sm[1] : docIdx;
      if (storageIdx !== null && !referencedStorage[storageIdx]) ops.push(deletePhotoFromStorage(o.id, storageIdx));
    });
  }catch(e){ console.warn("photo cleanup enumeration failed (proceeding — nothing overwritten)", e); }
  await Promise.all(ops);
  /* This device is now in sync with the cloud at main.savedAt -- advance the
     local base so its OWN subsequent saves don't false-conflict against the
     version it just wrote. Runs before the throws below so a partial-upload
     retry still starts from the right base. */
  o._cloudBaseSavedAt = main.savedAt;
  try{ var sdb = loadDb(); if (sdb.orders[o.id]){ sdb.orders[o.id]._cloudBaseSavedAt = main.savedAt; saveDb(sdb); } }catch(e){}
  if (uploadFailures > 0){
    throw new Error(uploadFailures + " photo" + (uploadFailures === 1 ? "" : "s") +
      " (photo " + failedPhotoNums.join(", ") + ") couldn't be uploaded to cloud storage. Your work order and these photos are safe on this device — tap “Retry now” on the sync banner (or Save again) to finish uploading them; they will NOT be dropped locally until they're in the cloud.");
  }
  if (preservedCount > 0){
    throw new Error(preservedCount + " photo" + (preservedCount === 1 ? "" : "s") +
      " on this device had no image data to save (likely an older cached copy) — the existing cloud photo(s) were kept, nothing was lost, but reload this work order to see them.");
  }
}
async function cloudFetchIndex(){
  if (!fdb) return [];
  var qs = await fdb.collection("workorders").orderBy("savedAt", "desc").limit(100).get();
  var arr = [];
  qs.forEach(function(d){
    var v = d.data();
    arr.push({ id: d.id, jobName: v.jobName || "(untitled)", jobNo: v.jobNo || "",
      location: v.location || "", serviceDate: v.serviceDate || "", savedAt: v.savedAt || 0, cloud: true,
      companyCamProjectId: v.companyCamProjectId || null,
      lastEmailedAt: v.lastEmailedAt || null, lastEmailedTo: v.lastEmailedTo || [] });
  });
  return arr;
}
async function cloudFetchOrder(id){
  if (!fdb) return null;
  var ref = fdb.collection("workorders").doc(id);
  var snap = await ref.get();
  if (!snap.exists) return null;
  var o = snap.data();
  o.id = id;
  /* The cloud version this copy descends from -- the base for the multi-device
     clobber guard in cloudSaveOrder(). Preserved through local caching
     (stripPhotoBytes copies it) and edits (saveOrder carries it forward). */
  o._cloudBaseSavedAt = o.savedAt || 0;
  var photosArr = [];
  try{
    var ps = await ref.collection("photos").get();
    ps.forEach(function(d){
      var v = d.data();
      /* storageRef/thumb are the current shape (see cloudSaveOrder() above)
         -- img is kept for backward compatibility with a photo doc saved
         BEFORE the Storage migration (still holds its full base64 bytes
         directly in Firestore, no storageRef at all yet); a migrated or
         freshly-captured photo relies on storageRef + resolvePhotoImg()
         instead. See "Photo storage migration" in DEV_NOTES.md.

         Deliberately NOT hydrated when a storageRef already exists, even
         though Firestore may still be holding a base64 backup there too
         (see cloudSaveOrder()'s cooling-off-period preservation) --
         cloudSaveOrder uses "does this photo carry .img client-side" as
         its ONLY signal for "the user captured/attached a new image this
         session, upload it." Hydrating the backup here would make every
         ordinary load->save of an already-migrated photo look exactly
         like a fresh capture: it would get needlessly re-uploaded, and
         -- because a real fresh upload intentionally does NOT re-carry an
         old backup forward -- the very backup being round-tripped would
         get silently dropped again right after being restored. Caught by
         testing: this happened for real immediately after restoring St
         Joe Hospital's photos. */
      /* Real production incident, 2026-07-12: every photo migrated to
         Storage by the one-time migrate_photo backfill (see "Photo storage
         migration" in DEV_NOTES.md) has storageRef but no thumb -- thumb
         generation only ever happened client-side at fresh-capture time
         (makeThumbDataUrl()), never during that server-side migration. So
         every migrated photo hit BOTH halves of this hydration at once:
         img forced null (storageRef present) AND thumb genuinely empty --
         nothing left to render, even though the real base64 bytes are
         sitting right here in v.img, completely intact (confirmed live
         against production: all 37 photos had img present, 0 had thumb).
         "Captions but no photos" was this, not data loss.
         imgFallback is a SEPARATE field, display-only -- deliberately NOT
         named img, so cloudSaveOrder()'s "does this photo carry .img
         client-side" fresh-capture-upload trigger is completely unaffected
         by it (see the CRITICAL DATA-LOSS GUARD comment on cloudSaveOrder()
         for why that signal has to stay exactly what it is). Only
         populated when thumb is missing -- once a photo has a real thumb
         (freshly captured, or backfilled), this is never touched. */
      /* ccFeedPhotoId is hydrated here for the same reason it's written in
         cloudSaveOrder(): it's the record that this photo has ALREADY been
         pushed into the linked CompanyCam project's photo feed. Without it on
         the client-side photo object, re-opening a work order and re-sending it
         would push every photo a second time -- see pushPhotosToCompanyCamFeed()
         in js/history.js. */
      photosArr[v.i] = { caption: v.caption || "", img: v.storageRef ? null : (v.img || null), w: v.w || 0, h: v.h || 0,
        finding_id: v.finding_id || null, ccPhotoId: v.ccPhotoId || null, gps: v.gps || null,
        ccFeedPhotoId: v.ccFeedPhotoId || null,
        storageRef: v.storageRef || null, thumb: v.thumb || null,
        imgFallback: (!v.thumb && v.storageRef) ? (v.img || null) : null };
    });
  }catch(e){}
  o.photos = photosArr.filter(Boolean);
  delete o.photoCount;
  return o;
}
async function cloudDeleteOrder(id){
  if (!fdb) return;
  var ref = fdb.collection("workorders").doc(id);
  try{
    var ps = await ref.collection("photos").get();
    var ops = [];
    ps.forEach(function(d){ ops.push(d.ref.delete()); });
    await Promise.all(ops);
  }catch(e){}
  await ref.delete();
}
function cloudErrMsg(e){
  var m = (e && e.message) ? String(e.message) : "unknown error";
  if (m.indexOf("permission") > -1 || m.indexOf("PERMISSION") > -1)
    return "Cloud save blocked \u2014 open Firebase \u2192 Firestore \u2192 Rules and allow read/write (rules may have expired).";
  if (m.indexOf("offline") > -1 || m.indexOf("network") > -1 || m.indexOf("unavailable") > -1)
    return "No internet \u2014 saved on this device only. It will need a re-save when you're back online.";
  return "Cloud save failed: " + m + " \u2014 saved on this device only.";
}

/* ================= building / customer history foundation =================
   Foundation for the RoofOps building-history vision: every building/roof
   should accumulate a timeline of work orders, repairs, photos and reports
   over its lifetime. This section does NOT change the existing work order
   workflow \u2014 it silently derives customer + building records from the
   existing Bill To / Job Name / Location fields whenever a work order is
   saved or a report is generated, and links history events to them. */
function slugify(s){
  return String(s || "").toLowerCase().trim()
    .replace(/[^a-z0-9]+/g, "-").replace(/^-+|-+$/g, "").slice(0, 80) || "unknown";
}
/* THE canonical name→id derivation (audit FIX 1). This exact formula used
   to be hand-copied in five files (workorders/core/dpr/history/export) —
   any drift between copies silently forked buildings. It now lives here
   ONLY; every other site calls these. Note this is the LEGACY/FALLBACK
   identity: saved work orders carry a stored buildingId/customerId
   (stamped by saveOrder() via ensureCustomerAndBuilding()) and readers
   prefer that, deriving from names only for legacy docs that predate the
   stored id and for a form that's never been saved/picked yet. */
function customerIdFor(billTo){
  var custName = (billTo || "").trim();
  return custName ? ("cust_" + slugify(custName)) : null;
}
function buildingIdFor(billTo, jobName){
  var bldName = (jobName || "").trim();
  if (!bldName) return null;
  return "bld_" + slugify((customerIdFor(billTo) || "nocust") + "_" + bldName);
}
async function ensureCustomerAndBuilding(o){
  if (!fdb) return { customerId: (o.customerId || null), buildingId: (o.buildingId || null) };
  var custName = (o.billTo || "").trim();
  var bldName = (o.jobName || "").trim();
  /* STORED identity wins (FIX 1): an order that already carries ids keeps
     writing to the SAME customer/building docs even after the tech renames
     the job or fixes a typo — the rename UPDATES the building's name below
     instead of forking a brand-new building that would strand its history,
     base map, and CompanyCam link. Names only derive ids for legacy docs
     and first saves. */
  var custId = o.customerId || customerIdFor(o.billTo);
  var bldId = o.buildingId || buildingIdFor(o.billTo, o.jobName);
  /* No job name: nothing safe to write (a stored-id order must not get its
     building name blanked either) — but still hand back whatever identity
     the order already carries so callers never "lose" a stored id. */
  if (!bldName || !bldId) return { customerId: custId || null, buildingId: (o.buildingId || null) };
  try{
    if (custId){
      await fdb.collection("customers").doc(custId).set({
        name: custName, updatedAt: Date.now()
      }, { merge: true });
    }
    var bldRef = fdb.collection("buildings").doc(bldId);
    var snap = await bldRef.get();
    var patch = {
      name: bldName, customerId: custId || null, customerName: custName || "",
      location: o.location || "", roofSystem: o.roofSystem || "",
      updatedAt: Date.now()
    };
    if (o.companyCamProjectId) patch.companyCamProjectId = o.companyCamProjectId;
    /* Foundation (construction-accounting) job link — the durable per-site
       identity from the system of record, persisted onto the building exactly
       like companyCamProjectId so every form for this site inherits it and the
       base-map resolver can follow the site by Foundation job (Step 3). Set by
       the Foundation job picker (issue #76, js/workorders.js) via collect();
       these lines are inert until that lands. Only ever ADD the link (never
       null it out here) so a stray unlinked save can't wipe a building's job
       reference. foundationAddress snapshots the accounting address even if the
       tech later edits the form's location field. */
    if (o.foundationJobNo) patch.foundationJobNo = o.foundationJobNo;
    if (o.foundationCustomerNo) patch.foundationCustomerNo = o.foundationCustomerNo;
    if (o.foundationAddress) patch.foundationAddress = o.foundationAddress;
    if (!snap.exists){
      patch.createdAt = Date.now();
      /* roof_base_map_type/url/bounds are set later via admin.js's
         set_building_roof_map (see DEV_NOTES.md) \u2014 seeded null here just so
         a fresh building doc shows the full schema shape in Firestore. */
      patch.roof_base_map_type = null;
      patch.roof_base_map_url = null;
    }
    await bldRef.set(patch, { merge: true });
    try{
      var freshBld = snap.exists ? Object.assign({}, snap.data(), patch) : patch;
      var roofs = getBuildingRoofs(freshBld);
      if (roofs.length === 1){
        roofs[0].roofSystem = patch.roofSystem;
        await saveBuildingRoofs(bldId, roofs);
      }
      /* A building with 2+ real roofs has no single target for a work
         order's roof system — work orders aren't roof-scoped yet (see
         DATA_MODEL.md), so multi-roof buildings just skip this sync until
         that's built. The legacy/singular fields above are unaffected
         either way. */
    }catch(e){ console.warn("roof sync failed", e); }
  }catch(e){ console.warn("customer/building sync failed", e); }
  return { customerId: custId, buildingId: bldId };
}

/* ================= building roofs data layer =================
   A building can have one or more roofs. Each roof carries its own copy
   of what used to be building-level fields: roofSystem, roof_base_map_*,
   roof_assets[], roof_outlines[]. See DATA_MODEL.md for the full design.

   Backward compatibility is load-bearing: dev and production share one
   live Firestore, and production's code only ever reads the OLD singular
   fields directly on the building doc. So:
   - getBuildingRoofs() is a pure read-time adapter, never writes anything.
     A building with a real roofs[] array uses it as-is. Any other
     building (never touched by this feature, or brand new) gets a single
     virtual roof synthesized from its existing singular fields, id
     "roof_default", label "Roof 1" — so every existing building looks
     exactly like it does today, with zero migration.
   - saveBuildingRoofs() always writes the new roofs[] array, AND mirrors
     roofs[0] back onto the legacy singular fields whenever the building
     still has exactly one roof — so production, which only reads those
     singular fields, keeps seeing correct, current data for every
     still-single-roof building (all of them, as of this writing). Once a
     building has a second real roof, there's no single roof left to
     mirror, so the legacy fields stop updating for that specific
     building — production would show that building's last-synced
     single-roof snapshot until this feature ships to main. That's a
     deliberate, called-out limit of dual-write, not an oversight: it only
     applies to a building actively using the brand-new capability that
     doesn't exist on production regardless. */
function getBuildingRoofs(bld){
  bld = bld || {};
  if (Array.isArray(bld.roofs) && bld.roofs.length) return bld.roofs;
  return [{
    id: "roof_default",
    label: "Roof 1",
    roofSystem: bld.roofSystem || "",
    roof_base_map_type: bld.roof_base_map_type || null,
    roof_base_map_url: bld.roof_base_map_url || null,
    roof_base_map_bounds: bld.roof_base_map_bounds || null,
    roof_base_map_synthetic: bld.roof_base_map_synthetic || false,
    roof_assets: bld.roof_assets || [],
    roof_outlines: bld.roof_outlines || []
  }];
}
function getRoofById(bld, roofId){
  var roofs = getBuildingRoofs(bld);
  return roofs.find(function(r){ return r.id === roofId; }) || roofs[0];
}
/* getBuildingRoofs() above defaults a building's first roof to literally
   "Roof 1" -- so a tech adding a second roof later, without visibility into
   what's already there, very easily retypes the same name (this is exactly
   how Mark ended up with two roofs both named "Roof 1" and no way to tell
   them apart). Case-insensitive/trimmed match; excludeRoofId lets a rename
   compare against every OTHER roof without flagging itself as a duplicate
   of its own current name. Auto-suggests "{label} (2)", "(3)", ... instead
   of just refusing, since the tech may genuinely want two similarly-named
   roofs (e.g. "Warehouse" + "Warehouse (2)" for a building with two). See
   "Rename a roof, discoverable from RoofMapper" in DEV_NOTES.md. */
function rmSuggestUniqueRoofLabel(roofs, label, excludeRoofId){
  var norm = function(s){ return String(s || "").trim().toLowerCase(); };
  var taken = (roofs || [])
    .filter(function(r){ return r.id !== excludeRoofId; })
    .map(function(r){ return norm(r.label); });
  if (taken.indexOf(norm(label)) === -1) return { isDuplicate: false, suggestion: label };
  var n = 2, candidate;
  do {
    candidate = label + " (" + n + ")";
    n++;
  } while (taken.indexOf(norm(candidate)) > -1);
  return { isDuplicate: true, suggestion: candidate };
}
/* Shared duplicate-name guard used by every place a roof label gets typed
   in (new-roof creation, rename from Building History, rename from
   RoofMapper) -- one consistent warn/auto-suggest/retry experience so a
   tech can never again end up with two same-named roofs on one building
   and no way to tell them apart. Loops so retyping another duplicate on
   retry gets caught too, not just the first attempt. Returns the label to
   save, or null if the tech backed out entirely. */
function rmResolveUniqueRoofLabel(roofs, label, excludeRoofId){
  while (true){
    var check = rmSuggestUniqueRoofLabel(roofs, label, excludeRoofId);
    if (!check.isDuplicate) return label;
    var useSuggested = confirm(
      "A roof on this building is already named \"" + label + "\".\n\n" +
      "OK to use \"" + check.suggestion + "\" instead, or Cancel to type a different name."
    );
    if (useSuggested) return check.suggestion;
    var retry = prompt("Name for this roof:", label);
    if (retry === null) return null;
    retry = retry.trim();
    if (!retry){ toast("Enter a name for the roof."); return null; }
    label = retry;
  }
}
async function saveBuildingRoofs(buildingId, roofs){
  var patch = { roofs: roofs, updatedAt: Date.now() };
  if (roofs.length === 1){
    var r = roofs[0];
    patch.roofSystem = r.roofSystem || "";
    patch.roof_base_map_type = r.roof_base_map_type || null;
    patch.roof_base_map_url = r.roof_base_map_url || null;
    patch.roof_base_map_bounds = r.roof_base_map_bounds || null;
    patch.roof_assets = r.roof_assets || [];
    patch.roof_outlines = r.roof_outlines || [];
  }
  await fdb.collection("buildings").doc(buildingId).set(patch, { merge: true });
}

/* ================= roof profile (admin-editable roof facts) =================
   A permanent profile of facts ABOUT a roof, as opposed to its living
   blueprint (roof_assets/roof_outlines, editable by any tech) or its
   history (building_history_events, one entry per report/activity).
   Lives at roof.profile — a brand-new nested object, not a rename of any
   existing field, so it needs no legacy-field mirroring at all: there was
   never a building-level equivalent for production's old code to read.
   Visible to everyone (plain client read, same as every other roof
   field); editing goes through admin.js's set_roof_profile action rather
   than a direct client write, for the same reason the custom base map
   does (see renderBaseMapAdminCard) — a shared, building-wide fact worth
   the extra server-enforced gate, not per-work-order draft data. `roofSystem`
   itself stays a top-level roof field (pre-existing, not moved under
   profile) — the profile card edits it directly rather than duplicating it. */
var ROOF_PROFILE_FIELDS = ["installDate", "estimatedAgeYears", "healthScore", "condition",
  "manufacturer", "deckType", "insulationType", "warrantyProvider", "warrantyExpiration",
  "warrantyStatus", "drainageNotes", "customerContacts", "internalNotes",
  "replacementHistory", "estimatedRemainingLifeYears"];
var ROOF_CONDITION_OPTIONS = ["Excellent", "Good", "Fair", "Poor", "Critical"];
var ROOF_WARRANTY_STATUS_OPTIONS = ["Active", "Expired", "Unknown"];
function getRoofProfile(roof){
  return (roof && roof.profile) || {};
}

/* ================= admin mode =================
   Auth Phase 5 (see docs/AUTH_DESIGN.md): isAdmin is now derived from the
   signed-in user's Firebase custom claims (owner, or role:"admin") -- the
   PIN is no longer checked by any mutating server action (netlify/
   functions/admin.js/photos.js/changeorders.js/send-workorder.js all
   verify a Firebase ID token + the caller's live roles/{role} permission
   grid instead). isAdmin here only controls which buttons/panels this
   client SHOWS -- exactly the "UI hiding is convenience only, never the
   boundary" rule already established in docs/AUTH_DESIGN.md's Enforcement
   section. A signed-in user whose role has SOME but not all of this bar's
   underlying permissions (e.g. service_manager has audit.view but isn't
   admin/owner) won't see this specific bar yet -- a known, deliberate UI
   scoping gap for tonight, not a security one: every action behind this
   bar independently re-checks its own specific permission server-side
   regardless of what this bar shows. */
var isAdmin = false;
function recomputeIsAdmin(){
  isAdmin = !!(currentAuthClaims && (currentAuthClaims.owner === true || currentAuthClaims.role === "admin"));
  updateAdminUI();
  updateServiceManagerUI();
}
/* Service-Manager-and-up gate for the dispatch/proposals workspace. Same
   claims-based, UI-only convenience as isAdmin (see the "admin mode" comment
   above): owner + admin + ops_manager + service_manager — the EXACT role set
   that already holds warranty.manage_reports, which server-gates the proposal
   source (contacts-sync). No new permission key: WO writes are client-direct
   under the existing open `workorders` rules and the proposal source is
   already gated, so there is nothing new to enforce server-side in v1. See the
   header of js/servicemanager.js. */
function canServiceManage(){
  if (!currentAuthClaims) return false;
  if (currentAuthClaims.owner === true) return true;
  var r = currentAuthClaims.role;
  return r === "admin" || r === "ops_manager" || r === "service_manager";
}
/* Shows/hides the Service Manager tab off the signed-in user's real role, the
   same pattern updateAdminUI() uses for tab-admin. Bounces off the SM view if
   access is revoked while it's open. */
function updateServiceManagerUI(){
  var tab = document.getElementById("tab-servicemanager");
  var can = canServiceManage();
  if (tab) tab.style.display = can ? "" : "none";
  if (!can && typeof currentViewName !== "undefined" && currentViewName === "servicemanager"){
    showView("edit");
  }
}
/* Attaches the signed-in user's Firebase ID token as a Bearer header --
   the actual trust boundary every claims-gated server function verifies
   via admin.auth().verifyIdToken(). Silently omitted if nobody's signed
   in; the server rejects with 401 in that case, same as any other
   missing-token call. */
async function authHeaders(){
  var h = { "Content-Type": "application/json" };
  if (fauth && currentAuthUser){
    try{ h["Authorization"] = "Bearer " + (await currentAuthUser.getIdToken()); }catch(e){}
  }
  return h;
}
/* Read-only search over active Foundation (construction-accounting) jobs, for
   the Foundation job picker (issue #76, js/workorders.js). Returns the mapped
   job list [{ job_no, name, customer_no, project_manager_no, address, city,
   state, zip }] or [] on any failure, so the picker degrades to "no matches"
   rather than throwing. The connector is read-only; this never writes. */
async function fetchFoundationJobs(search){
  try{
    var qs = search ? ("&search=" + encodeURIComponent(String(search).slice(0, 100))) : "";
    var r = await fetch("/.netlify/functions/foundation?action=jobs" + qs, {
      method: "GET", headers: await authHeaders()
    });
    if (!r.ok) return [];
    var out = await r.json().catch(function(){ return null; });
    return (out && Array.isArray(out.jobs)) ? out.jobs : [];
  }catch(e){ return []; }
}
/* Admin-triggered Foundation job sync -- forces the same read-only pull the
   scheduled hourly Action runs (netlify/functions/foundation-sync.js), so an
   admin can refresh the job picker on demand. The function is server-gated:
   the caller must hold foundation.read (or be the scheduled secret), so a
   non-permitted user just gets a clear 403 toast. Wired to the admin-only
   "Sync Foundation Jobs Now" button; disables the button while in flight. */
async function runFoundationSync(btn){
  if (btn) btn.disabled = true;
  toast("Syncing Foundation jobs…");
  try{
    var r = await fetch("/.netlify/functions/foundation-sync", {
      method: "POST", headers: await authHeaders(),
      body: JSON.stringify({ action: "sync" })
    });
    var out = null; try{ out = await r.json(); }catch(e){}
    if (!r.ok || !out || out.ok === false){
      toast("Foundation sync failed: " + ((out && out.error) || ("server error " + r.status)));
    } else {
      var n = (out.active_jobs != null) ? out.active_jobs : "?";
      toast("Foundation jobs synced ✓ — " + n + " active job" + (out.active_jobs === 1 ? "" : "s") +
        (out.written != null ? " (" + out.written + " updated)" : "") + ".");
    }
  }catch(e){
    toast("Foundation sync failed: " + (e && e.message ? e.message : "network error"));
  }finally{
    if (btn) btn.disabled = false;
  }
}
