/* Downscales an already-captured canvas the same way resizeImageFile()
   downscales a source <img> -- kept separate since there's no File/Image
   to read here, just a canvas html2canvas already produced. Caps the
   screenshot well under Firestore's 1MB document limit and keeps the
   emailed attachment small. */
function canvasToCappedDataUrl(canvas, maxDim, quality){
  var w = canvas.width, h = canvas.height;
  if (w > maxDim || h > maxDim){
    if (w >= h){ h = Math.round(h * maxDim / w); w = maxDim; }
    else { w = Math.round(w * maxDim / h); h = maxDim; }
  }
  var c = document.createElement("canvas");
  c.width = w; c.height = h;
  c.getContext("2d").drawImage(canvas, 0, 0, w, h);
  return c.toDataURL("image/jpeg", quality);
}
async function captureFeedbackScreenshot(){
  if (!window.html2canvas){ toast("Screenshot tool isn't available right now — try Attach Photo instead."); return; }
  toast("Capturing screen…");
  var modal = document.getElementById("feedback-modal");
  modal.style.display = "none"; /* don't capture the feedback modal itself */
  try{
    await new Promise(function(r){ setTimeout(r, 50); });
    var canvas = await html2canvas(document.body, { scale: 1, logging: false, useCORS: true });
    feedbackState.screenshot = canvasToCappedDataUrl(canvas, 900, 0.55);
    renderFeedbackScreenshotStatus();
    toast("Screenshot captured ✓");
  }catch(e){
    toast("Couldn't capture the screen — try Attach Photo instead.");
  }finally{
    modal.style.display = "";
  }
}
function attachFeedbackPhoto(input){
  var file = input.files && input.files[0];
  input.value = "";
  if (!file) return;
  resizeImageFile(file, 900, 0.55).then(function(dataUrl){
    feedbackState.screenshot = dataUrl;
    renderFeedbackScreenshotStatus();
    toast("Photo attached ✓");
  }).catch(function(e){ toast("Couldn't read that photo: " + e.message); });
}
function renderFeedbackScreenshotStatus(){
  var host = document.getElementById("feedback-screenshot-status");
  if (!host) return;
  host.innerHTML = feedbackState.screenshot ?
    '<img src="' + feedbackState.screenshot + '" style="max-width:160px;max-height:110px;border:1px solid var(--line);border-radius:4px;display:block;margin-top:6px">' +
    '<button class="btn danger" style="margin-top:6px" onclick="removeFeedbackScreenshot()">Remove</button>' : '';
}
function removeFeedbackScreenshot(){
  feedbackState.screenshot = null;
  renderFeedbackScreenshotStatus();
}
async function submitFeedback(){
  if (!feedbackState.type){ toast("Pick a feedback type first."); return; }
  var typeInfo = FEEDBACK_TYPES.find(function(t){ return t.key === feedbackState.type; });
  var comments = val("feedback-comments").trim();
  var onWorkOrderScreen = currentViewName === "edit" || currentViewName === "preview";
  var techFromForm = onWorkOrderScreen ? val("technician").trim() : "";
  var techName = techFromForm || (getFieldHistory("technician")[0] || "");
  var doc = {
    type: feedbackState.type,
    typeLabel: typeInfo.emoji + " " + typeInfo.label,
    comments: comments,
    screen: FEEDBACK_VIEW_LABELS[currentViewName] || currentViewName,
    technician: techName,
    adminMode: isAdmin,
    device: (navigator.userAgent || "").slice(0, 200),
    workOrderId: onWorkOrderScreen ? (currentId || null) : null,
    workOrderJobName: onWorkOrderScreen ? (val("jobName").trim() || null) : null,
    screenshot: feedbackState.screenshot || null,
    createdAt: Date.now()
  };
  toast("Sending feedback…");
  var savedOk = false, emailOk = false;
  if (fdb){
    try{
      await fdb.collection("feedback").doc(genId("fb")).set(doc);
      savedOk = true;
    }catch(e){ /* still try the email below */ }
  }
  try{
    var resp = await fetch("/.netlify/functions/send-feedback", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify(doc)
    });
    var out = null;
    try{ out = await resp.json(); }catch(e){}
    emailOk = !!(resp.ok && out && out.ok);
  }catch(e){ /* best-effort -- backlog storage above is what matters most */ }
  closeFeedbackModal();
  if (savedOk || emailOk) toast("Feedback sent — thank you! ✓");
  else toast("Couldn't send feedback — check your connection and try again.");
}
