/* ================= collect / fill ================= */
/* Extensible on purpose — adding a new type is just adding a string here.
   "Leak / Service" MUST stay first: it's the default for both a brand-new
   work order and any existing one saved before this field existed (see
   collect()/fill() below), so today's behavior never changes for the
   common case. Only "Change Order" currently reveals extra fields
   (#wo-changeorder-card) — the rest just get recorded, not built out
   further yet, per spec ("don't over-build"). */
var WORK_ORDER_TYPES = ["Leak / Service", "Change Order", "Inspection", "Repair", "Warranty"];
/* Icon + display label for the home-screen launcher tiles (see
   renderHomeTiles() below) — keyed by the same WORK_ORDER_TYPES strings,
   so adding a new type there and here is the only step needed for it to
   get its own tile automatically. Falls back to the type string itself
   if a label override isn't given (only "Leak / Service" needs one —
   "Leak Work Order" reads better as a tile than the raw type value). */
var WORK_ORDER_TYPE_ICONS = {
  "Leak / Service": "💧", "Change Order": "📝", "Inspection": "🔍",
  "Repair": "🔧", "Warranty": "🛡️"
};
/* DISPLAY-ONLY label overrides. The STORED value on a work order is still
   the raw WORK_ORDER_TYPES string ("Repair", "Leak / Service", ...) — this
   map only changes what a human sees. "Repair" now renders as "Work Order"
   (Mark: a Work Order executes predetermined work already sold on a
   proposal). Every already-saved repair work order keeps woType "Repair"
   in Firestore and in building_history_events.workOrderType — it still
   loads, still matches, still filters, and simply DISPLAYS as "Work
   Order". No migration, no rewrite of stored values. WORK_ORDER_TYPES
   above is deliberately unchanged. Route EVERY user-visible rendering of a
   type through woTypeLabel() — form dropdown, report/PDF, timeline and
   reports chips, type filters. See "Repair -> Work Order rename" in
   DEV_NOTES.md. */
var WORK_ORDER_TYPE_LABELS = { "Leak / Service": "Leak Work Order", "Repair": "Work Order" };
function woTypeLabel(t){
  var raw = t || WORK_ORDER_TYPES[0];
  return WORK_ORDER_TYPE_LABELS[raw] || raw;
}

/* EMAIL COPY ONLY — the wording used in the outgoing email subject/body.
   Deliberately separate from woTypeLabel(): in the app a leak job is still a
   "Leak Work Order" on the form, but the customer-facing EMAIL must never say
   "Leak". Both the leak type ("Leak / Service") and the plain work order
   ("Repair", displayed as "Work Order") send as "Service Work Order"; Change
   Order, Inspection and Warranty keep their own wording. Stored woType values
   are untouched. */
var EMAIL_TYPE_COPY = {
  "Change Order": { subject: "Change Order", noun: "Change order" },
  "Inspection":   { subject: "Inspection",   noun: "Inspection" },
  "Warranty":     { subject: "Warranty",     noun: "Warranty" }
};
function emailTypeSubject(t){
  var e = EMAIL_TYPE_COPY[t || ""];
  return e ? e.subject : "Service Work Order";
}
function emailTypeNoun(t){
  var e = EMAIL_TYPE_COPY[t || ""];
  return e ? e.noun : "Service work order";
}
function populateWoTypeSelect(){
  var sel = document.getElementById("woType");
  if (sel.options.length) return;
  WORK_ORDER_TYPES.forEach(function(t){
    var opt = document.createElement("option");
    /* value = the raw stored enum (unchanged, what collect() saves);
       textContent = the display label. Keeping these two apart is the
       whole point — setVal("woType", "Repair") on an existing record still
       matches an option, it just reads "Work Order" on screen. */
    opt.value = t; opt.textContent = woTypeLabel(t);
    sel.appendChild(opt);
  });
}
/* ---- AI "Draft Summary" capability gate ----------------------------------
   Whether THIS deploy has an AI key lives server-side only (the key is never
   shipped to the client), so the button's visibility is driven by a one-time
   capability probe rather than anything the page can read directly. Tri-state:
   null = not yet probed (button stays hidden — no flash of a dead control),
   true = a key is configured (dev today; prod once Mark provisions one),
   false = keyless deploy (production today — button stays hidden for good).
   Probed lazily the first time a summary-bearing type is selected, cached for
   the session, and re-applies the type gate (onWoTypeChange) once it resolves. */
var __aiSummaryConfigured = null;
var __aiSummaryProbe = null;
function aiSummaryConfigured(){ return __aiSummaryConfigured; }
function probeAiSummaryCapability(){
  if (__aiSummaryProbe) return __aiSummaryProbe;
  __aiSummaryProbe = (async function(){
    try{
      var r = await fetch("/.netlify/functions/generate-summary", {
        method: "POST", headers: await authHeaders(),
        body: JSON.stringify({ action: "capability" })
      });
      var out = null; try{ out = await r.json(); }catch(e){}
      __aiSummaryConfigured = !!(r.ok && out && out.ok && out.configured);
    }catch(e){
      /* Network/permission hiccup: treat as unconfigured (hide the button) —
         a missing draft button is a non-event; a broken one is not. */
      __aiSummaryConfigured = false;
    }
    if (typeof onWoTypeChange === "function") onWoTypeChange();
    return __aiSummaryConfigured;
  })();
  return __aiSummaryProbe;
}
function onWoTypeChange(){
  var isCO = val("woType") === "Change Order";
  var el = document.getElementById("wo-changeorder-card");
  if (el) el.style.display = isCO ? "" : "none";
  if (isCO) renderChangeOrderPhotos();
  /* Change Order-only autofill: adopt the building's existing CompanyCam
     link (so the signed CO PDF actually pushes -- see
     resolveBuildingCompanyCamLink() in js/companycam.js) and default the
     Job No. to the parent job's number + " CO" (see
     maybeApplyChangeOrderJobNo() in js/workorders.js). Both are no-ops for
     every other type, both are pure defaults the tech can override, and
     neither ever creates a CompanyCam project. typeof-guarded because
     js/workorders.js loads after this file. */
  if (isCO && typeof scheduleChangeOrderAutofill === "function") scheduleChangeOrderAutofill();
  var isRepair = val("woType") === "Repair";
  var rc = document.getElementById("wo-repair-card");
  if (rc) rc.style.display = isRepair ? "" : "none";
  /* Material List: Work Order (Repair), Leak / Service AND Change Order
     (Mark: "a change order form needs materials too"). Repair/Leak were
     added earlier (the Repair-only gate had made the card look "missing" on
     the Leak form — a leak call burns material too). Change Order now uses
     this SAME itemized list as its primary materials entry; the old
     free-text #woMaterials inside its card is demoted to a clearly-labelled
     "Additional Material Notes" legacy field, shown only when it already
     carries text (see the co-materials-legacy gate below) so no existing CO
     record loses that data. Inspection stays out; WARRANTY is a pending
     decision from Mark — deliberately NOT added yet. DISPLAY GATING ONLY —
     like repairs[], collect()/fill() round-trip materials[] for every type,
     and the report builders print materials whenever present (the three
     Change Order builders were taught to print the itemized list too — see
     export.js). (WORK_ORDER_TYPES[0] is checked inline — the isLeakType var
     is only declared further down in this function; don't reference it
     before its declaration.) */
  var mc = document.getElementById("wo-materials-card");
  if (mc) mc.style.display = (isRepair || isCO || val("woType") === WORK_ORDER_TYPES[0]) ? "" : "none";
  /* Legacy Change Order free-text materials (#woMaterials, wrapped in
     #wo-co-materials-legacy): the itemized Material List above is now the
     primary entry on a Change Order, so this field is hidden for new work
     rather than presenting a confusing second "Materials" box. It is
     revealed ONLY on a Change Order that already has text in it — an
     existing record — so that data stays visible, editable and preserved on
     the next save. fill() sets #woMaterials before calling this function, so
     the value is already in place when we check it. */
  var coLegacy = document.getElementById("wo-co-materials-legacy");
  if (coLegacy) coLegacy.style.display = (isCO && String(val("woMaterials") || "").trim()) ? "" : "none";
  /* Repair is a project/scope report, not a leak diagnosis — findings
     (leak pins/conditions) don't apply to it, per Mark. Change Order is a
     scope of work, not a leak diagnosis either — same reasoning. */
  var fc = document.getElementById("wo-findings-card");
  if (fc) fc.style.display = (isRepair || isCO) ? "none" : "";
  /* Change Order has no repairs-made concept (it IS the work being
     authorized, described in its own Description field) — hide the
     generic "Work Performed" section for it. A Leak Work Order is now a
     PURE leak investigation (Mark): findings, roof map + pins, photos,
     warranty determination, summary — and nothing about repair scope.
     Work actually performed belongs on a Work Order (stored value
     "Repair"), the type that executes predetermined scope already sold on
     a proposal. Repair/Inspection/Warranty keep this card exactly as
     before. DISPLAY GATING ONLY — collect() still writes repairs[] and
     fill() still loads it for EVERY type, so an existing leak record that
     already has repair rows keeps them byte-for-byte; they're simply no
     longer editable on the leak form (and its report still prints them —
     see buildLeakReportText()). No field removed, no data dropped, no
     migration. See "Leak form = pure leak investigation" in DEV_NOTES.md. */
  var isLeakType = val("woType") === WORK_ORDER_TYPES[0];
  var rpc = document.getElementById("wo-repairsperformed-card");
  if (rpc) rpc.style.display = (isCO || isLeakType) ? "none" : "";
  /* Change Order has its own in-scope photo box (#co-photos-host, inside
     wo-changeorder-card) — the global Photo Documentation section would
     just be a second, redundant place to add the exact same photos[]
     array, so hide it for Change Order only. Every other type keeps it
     exactly as before. */
  var gpc = document.getElementById("wo-globalphotos-card");
  if (gpc) gpc.style.display = isCO ? "none" : "";
  /* Photo capture buttons (Take Photo / Add Photos / Import from
     CompanyCam) moved up into each finding's own card for every type
     that HAS findings — same reasoning as photo-in-finding above: photos
     belong with the finding they document, captured/imported in one
     step, not added separately and linked up after. Repair is the one
     exception: it has no findings at all (see wo-findings-card above),
     so it's the only type left that still needs these buttons in the
     global section — otherwise a Repair work order would have no way to
     add a photo at all. Change Order's global section is already fully
     hidden above, so this is moot for it. */
  var hasFindings = !isRepair && !isCO;
  var gpb = document.getElementById("wo-globalphotos-buttons");
  if (gpb) gpb.style.display = hasFindings ? "none" : "";
  var hintFindings = document.getElementById("wo-globalphotos-hint-findings");
  if (hintFindings) hintFindings.style.display = hasFindings ? "" : "none";
  var hintNoFindings = document.getElementById("wo-globalphotos-hint-nofindings");
  if (hintNoFindings) hintNoFindings.style.display = hasFindings ? "none" : "";
  /* Warranty Determination doesn't apply to a Change Order at all — it's a
     scope-of-work/authorization document, not a leak/warranty
     investigation (per Mark, same framing as the findings/repairs-made
     sections above). Inspection doesn't need it either (per Mark, when
     building out the real Inspection form — an inspection isn't itself a
     warranty determination, that's a separate downstream decision).
     Every other type keeps the card exactly as before. */
  var isInspection = val("woType") === "Inspection";
  var wdc = document.getElementById("wo-warrantydetermination-card");
  if (wdc) wdc.style.display = (isCO || isInspection) ? "none" : "";
  /* Warranty guideline reference + Manufacturer Service # are leak-specific
     (per Mark: guideline lists are "for leaks and leaks only"; the
     manufacturer service # is what a warrantable leak usually also has a
     manufacturer work order for) — shown only for the default type. */
  var isLeak = val("woType") === WORK_ORDER_TYPES[0];
  var lw = document.getElementById("wo-leak-warranty-extra");
  if (lw) lw.style.display = isLeak ? "" : "none";
  /* Inspection form (built out per Mark's real-world feedback testing
     dev): no "Reported Leak Area" (that's a Leak/Service-specific intake
     field, an inspection isn't triggered by a reported leak), findings
     section relabeled since findings on an inspection are added one at a
     time as the tech works through the roof (not "investigation findings"
     from a specific leak complaint), and the new Inspection Checklist card
     -- see "Inspection form overhaul" in DEV_NOTES.md. */
  var raf = document.getElementById("wo-reportedarea-fld");
  if (raf) raf.style.display = isInspection ? "none" : "";
  /* "Draft Summary" (AI-drafted summary — see "AI-drafted report summary"
     in DEV_NOTES.md): Mark's three summary-bearing report types —
     Inspection, Leak, and Work Order (stored type "Repair") — all share the
     ONE #summary field and the ONE generate-summary server function; this
     only gates the button. Change Order (its own document, no Summary
     section in its PDF) and Warranty stay hidden — widening later is just
     this condition. */
  var dsr = document.getElementById("wo-draft-summary-row");
  /* Teaser, not a hard gate (Mark, 2026-07-17): show the "✨ Draft Summary"
     button on every summary-bearing report type (Inspection, Leak, Work Order)
     regardless of whether THIS deploy has an AI key. On a keyed deploy (dev, or
     prod once a key is provisioned) tapping generates a real draft; on a
     keyless deploy (production today) tapping shows a friendly "coming soon"
     toast instead of a dead no-op or an error — that branch lives in
     draftReportSummary() (js/workorders.js), driven by the same capability
     probe. Change Order (its own document, no Summary section in its PDF) and
     Warranty stay hidden — widening later is just this condition. */
  var wantsSummary = (isInspection || isLeakType || isRepair);
  if (dsr) dsr.style.display = wantsSummary ? "" : "none";
  /* Pre-warm the capability probe so a tap branches instantly (real draft vs
     coming-soon) without waiting on the round-trip. Cached + typeof-guarded for
     isolated-function unit tests and load order — same convention as the other
     neighbor calls here; draftReportSummary() also awaits it as a fallback if
     the button is tapped before this resolves. */
  if (wantsSummary && typeof aiSummaryConfigured === "function" && aiSummaryConfigured() === null &&
      typeof probeAiSummaryCapability === "function") probeAiSummaryCapability();
  var ic = document.getElementById("wo-inspection-card");
  if (ic) ic.style.display = isInspection ? "" : "none";
  if (isInspection){ ensureInspectionChecklist(); renderInspectionChecklist(); renderInspectionRoofPicker(); }
  var ft = document.getElementById("wo-findings-title");
  if (ft) ft.textContent = isInspection ? "Roofing Inspection Findings" : "Roof Investigation Findings";
  /* Building-level CompanyCam link control (#wo-cc-link-row): shown for the
     findings-based types (Leak / Inspection / Warranty) whose per-finding capture
     hid the global import row above -- so Inspection etc. finally have a visible
     way to LINK CompanyCam at the building level. Change Order/Repair are covered
     elsewhere (see ccBuildingLinkControlVisible in js/companycam.js). */
  var ccLinkVisible = typeof ccBuildingLinkControlVisible === "function" && ccBuildingLinkControlVisible(val("woType"));
  var ccRow = document.getElementById("wo-cc-link-row");
  if (ccRow) ccRow.style.display = ccLinkVisible ? "" : "none";
  var ccHint = document.getElementById("wo-cc-link-hint");
  if (ccHint) ccHint.style.display = ccLinkVisible ? "" : "none";
}

/* ================= storage ================= */
/* localStorage has a hard ~5-10MB per-origin quota, and every locally-cached
   work order embeds its photos as base64 directly in the cached JSON blob —
   that's what actually fills it up (see saveDb()'s QuotaExceededError catch
   below). Two safeguards keep that from happening just from normal use:
   1. Merely opening/viewing a report never caches its photo bytes locally —
      only an explicit Save (the order actively open in the Edit tab) does.
      See loadOrder() below; it still caches everything else (job info,
      findings, repairs, captions) via stripPhotoBytes(), just not the big
      base64 image data, so offline re-opening a previously-viewed report
      still shows everything except thumbnails.
   2. Even among actively-saved drafts, only the MAX_CACHED_PHOTO_DRAFTS most
      recently saved keep their photo bytes locally — older ones get
      stripped on the next save (pruneCachedPhotoDrafts(), called from
      saveOrder()). Nothing is lost: the cloud copy (Firestore) always has
      the full photos; this only affects what's available for offline
      editing on this device without a network round-trip. (The old
      exportOrder() had a similar carve-out for the same reason before it
      was removed entirely -- see "Export button removed" in
      DEV_NOTES.md.) */
var MAX_CACHED_PHOTO_DRAFTS = 5;
/* photosStripped is the explicit, checkable fact that this specific cached
   copy is missing real image bytes -- Mark's real bug: loadOrder() used to
   infer "is this cache good enough" purely from a savedAt timestamp
   comparison, but stripping never touches savedAt, so a stripped local
   copy and its cloud original can carry the exact same timestamp forever.
   The next time that report was reopened, the timestamp comparison found
   them "equal, nothing new on the cloud" and trusted the stripped local
   copy -- captions/findings intact, every photo silently empty, in BOTH
   the Preview view and the generated PDF (both render straight from
   whatever's currently in memory, by design -- see renderLeakReportDoc()'s
   own "synchronous, no Firestore access" comment). This flag is what
   loadOrder() now checks instead of trusting the timestamp alone -- see
   "PDF/preview missing photos" in DEV_NOTES.md. */
function stripPhotoBytes(o){
  var copy = Object.assign({}, o);
  copy.photos = (o.photos || []).map(function(p){
    var p2 = Object.assign({}, p);
    delete p2.img;
    return p2;
  });
  copy.photosStripped = true;
  return copy;
}
function orderHasCachedPhotoBytes(o){
  return !!(o && o.photos && o.photos.some(function(p){ return p && p.img; }));
}
/* Every photo that still has local bytes ALSO has a storageRef -- i.e. its bytes
   are safely in Firebase Storage and the local copy is just a cache we can drop.
   A photo with img but NO storageRef was never uploaded: its local bytes are the
   ONLY copy, so eviction MUST keep it (data-loss guard, Mark's #1 rule). */
function orderIsFullyCloudBacked(o){
  return !!(o && o.photos) && o.photos.every(function(p){ return !p || !p.img || !!p.storageRef; });
}
/* An order is safe to evict photo bytes from ONLY if it's not the one open now,
   not still waiting to sync, and every photo it holds is already in Storage. */
function orderPhotoBytesAreEvictable(db, orderId, pending){
  if (orderId === currentId) return false;
  if (pending && pending[orderId]) return false;
  var o = db.orders[orderId];
  return orderHasCachedPhotoBytes(o) && orderIsFullyCloudBacked(o);
}
/* Local record has photos worth caring about (findings/captions/etc. that
   imply real images belong here) but this specific cached copy doesn't
   actually have the bytes -- the exact condition loadOrder() must never
   silently trust over a cloud refetch.

   CRITICAL FIX: checking photosStripped alone missed every record that
   was ALREADY stripped in a tech's browser BEFORE that flag started being
   set (this fix shipped today -- any local cache entry written by the
   OLD stripPhotoBytes(), which never stamped the flag, is invisible to a
   flag-only check even though it's exactly as stripped). That's what let
   Mark's EDIT view open with zero photos even after the flag-based
   loadOrder() fix landed: his local cache predated the flag. Now also
   detects the SYMPTOM directly -- every photo entry has metadata
   (implying a real photo once existed here) but NONE carry any way to
   actually show one (no img, no storageRef, no thumb) -- regardless of
   whether photosStripped happens to be set. See "PDF/preview missing
   photos" and "Photo storage migration" in DEV_NOTES.md. */
function orderPhotosAreStrippedLocally(o){
  if (!o || !(o.photos && o.photos.length)) return false;
  if (o.photosStripped) return true;
  return o.photos.every(function(p){ return !p.img && !p.storageRef && !p.thumb; });
}
function pruneCachedPhotoDrafts(db){
  var pending = loadSyncQueue();
  var evictable = db.index.filter(function(e){
    return orderPhotoBytesAreEvictable(db, e.id, pending);
  }).sort(function(a, b){ return (b.savedAt || 0) - (a.savedAt || 0); });
  if (evictable.length <= MAX_CACHED_PHOTO_DRAFTS) return false;
  evictable.slice(MAX_CACHED_PHOTO_DRAFTS).forEach(function(e){
    if (db.orders[e.id]) db.orders[e.id] = stripPhotoBytes(db.orders[e.id]);
  });
  return true;
}
/* Emergency eviction when localStorage is FULL: drop the bytes of every order
   whose photos are safely in Storage (evictable), not just those over the cache
   cap -- a save must never be permanently blocked by quota while there is
   cloud-backed data we can free. Never touches the current order, a pending
   (unsynced) order, or a never-uploaded photo -- those local bytes may be the
   only copy. Returns whether anything was freed. */
function evictCloudBackedPhotoBytes(db){
  var pending = loadSyncQueue();
  var freed = false;
  db.index.forEach(function(e){
    if (orderPhotoBytesAreEvictable(db, e.id, pending)){
      db.orders[e.id] = stripPhotoBytes(db.orders[e.id]);
      freed = true;
    }
  });
  return freed;
}
function loadDb(){
  try{
    var raw = localStorage.getItem(STORE_KEY);
    if (raw) return JSON.parse(raw);
  }catch(e){}
  return { orders:{}, index:[] };
}
/* Serialization replacer that keeps the localStorage cache lean (Phase 1): a
   photo's full base64 img is OMITTED from what's written to localStorage once
   its bytes are safely elsewhere -- confirmed in IndexedDB (_idbBacked) or in
   Storage (storageRef). Un-backed photos keep their img (the only copy). A
   replacer only shapes the OUTPUT string; the in-memory photo objects are never
   mutated, so the open gallery still has its bytes. The condition is only ever
   true for photo objects (only they carry _idbBacked/storageRef), so unrelated
   img fields -- e.g. a Change Order signature's -- are untouched. localStorage's
   ~5MB ceiling is what started the storage saga; IndexedDB holds the bytes and
   resolvePhotoImg() rehydrates on demand. See "Photo bytes in IndexedDB" in
   DEV_NOTES.md. */
function leanDbReplacer(key, value){
  if (key === "img" && this && (this._idbBacked === true || this.storageRef)) return undefined;
  return value;
}
function saveDb(db){
  try{
    localStorage.setItem(STORE_KEY, JSON.stringify(db, leanDbReplacer));
    return true;
  }catch(e){
    var isQuota = e && (e.name === "QuotaExceededError" || String(e.message).toLowerCase().indexOf("quota") > -1);
    /* Quota hit -> free every photo that's safely in the cloud and RETRY, so a
       save is never permanently blocked while there's evictable data. Only the
       current order and still-unsynced photos keep their bytes. */
    if (isQuota && evictCloudBackedPhotoBytes(db)){
      try{ localStorage.setItem(STORE_KEY, JSON.stringify(db, leanDbReplacer)); return true; }
      catch(e2){ e = e2; }
    }
    if (isQuota){
      toast("Storage is full — finish syncing first (tap “Retry now” on the banner), or delete old saved work orders, then save again.");
    } else {
      toast("Save error: " + (e && e.message ? e.message : "storage unavailable"));
    }
    return false;
  }
}

/* ================= offline-first: IndexedDB photo backup =================
   Real production risk (Mark, 2026-07-12): commercial roofs are frequent
   dead zones, and localStorage alone can't reliably hold full-resolution
   photo bytes -- one shared ~5-10MB quota across every saved order (see
   saveDb()'s QuotaExceededError branch above, and pruneCachedPhotoDrafts()
   above that, which exists ONLY because of this limit). IndexedDB has a
   much higher quota (typically hundreds of MB+, browser/device-dependent)
   and is the right place for binary photo data.

   Deliberately ADDITIVE, not a replacement for the existing localStorage-
   based order cache -- every photo captured still flows through the exact
   same in-memory `photos` array and every existing save/load code path
   (cloudSaveOrder's CRITICAL DATA-LOSS GUARD, cloudFetchOrder's stripped-
   copy refusal, orderPhotosAreStrippedLocally -- all untouched, still
   exactly as hardened/tested tonight). Every photo ALSO gets mirrored into
   IndexedDB the instant it's captured (see makeLocalPhotoId()/photos.js),
   keyed by a stable id that never changes even if the photo is later
   reordered or removed from the array before Save -- pure insurance: if
   localStorage's write fails (quota), or the tab is killed before a Save
   ever happens, the real bytes are still recoverable here. */
var IDB_NAME = "roofops_offline";
var IDB_VERSION = 1;
var IDB_PHOTOS_STORE = "photoBlobs";
var idbOpenPromise = null;
function openIdb(){
  if (idbOpenPromise) return idbOpenPromise;
  idbOpenPromise = new Promise(function(resolve, reject){
    if (!window.indexedDB){ reject(new Error("IndexedDB not available in this browser")); return; }
    var req = indexedDB.open(IDB_NAME, IDB_VERSION);
    req.onupgradeneeded = function(){
      var idb = req.result;
      if (!idb.objectStoreNames.contains(IDB_PHOTOS_STORE)) idb.createObjectStore(IDB_PHOTOS_STORE);
    };
    req.onsuccess = function(){ resolve(req.result); };
    req.onerror = function(){ reject(req.error || new Error("IndexedDB open failed")); };
  });
  return idbOpenPromise;
}
function makeLocalPhotoId(){
  return "lp_" + Date.now().toString(36) + "_" + Math.random().toString(36).slice(2, 10);
}
async function idbPutPhoto(localId, dataUrl){
  if (!localId || !dataUrl) return false;
  try{
    var idb = await openIdb();
    return await new Promise(function(resolve, reject){
      var tx = idb.transaction(IDB_PHOTOS_STORE, "readwrite");
      tx.objectStore(IDB_PHOTOS_STORE).put(dataUrl, localId);
      tx.oncomplete = function(){ resolve(true); };
      tx.onerror = function(){ reject(tx.error); };
    });
  }catch(e){
    /* Never block the actual capture on this -- the photo is still safe
       in memory and (once Saved) in localStorage/the cloud, exactly as
       before this feature existed. This is extra insurance, not the only
       copy, so a failure here is logged, not surfaced as an error to the
       tech mid-capture. */
    console.warn("idbPutPhoto failed (photo still held normally, nothing lost)", e);
    return false;
  }
}
async function idbGetPhoto(localId){
  if (!localId) return null;
  try{
    var idb = await openIdb();
    return await new Promise(function(resolve){
      var tx = idb.transaction(IDB_PHOTOS_STORE, "readonly");
      var req = tx.objectStore(IDB_PHOTOS_STORE).get(localId);
      req.onsuccess = function(){ resolve(req.result || null); };
      req.onerror = function(){ resolve(null); };
    });
  }catch(e){ return null; }
}
async function idbDeletePhoto(localId){
  if (!localId) return false;
  try{
    var idb = await openIdb();
    return await new Promise(function(resolve){
      var tx = idb.transaction(IDB_PHOTOS_STORE, "readwrite");
      tx.objectStore(IDB_PHOTOS_STORE).delete(localId);
      tx.oncomplete = function(){ resolve(true); };
      tx.onerror = function(){ resolve(false); };
    });
  }catch(e){ return false; }
}
/* Best-effort recovery pass: for any photo in this order missing BOTH a
   renderable image (thumb/imgFallback/img) and Storage-uploaded bytes
   (storageRef), try IndexedDB via localId before giving up. Called before
   a cloud save attempt so a save-time recovery works exactly like a
   capture-time one -- the tech never needs to know this layer exists. */
async function idbRecoverPhotoBytes(o){
  var photos = (o && o.photos) || [];
  for (var i = 0; i < photos.length; i++){
    var p = photos[i];
    if (p && !p.img && !p.storageRef && p.localId){
      var recovered = await idbGetPhoto(p.localId);
      if (recovered) p.img = recovered;
    }
  }
  return o;
}
/* Offload already-cached photo bytes into IndexedDB so the next saveDb (via
   leanDbReplacer) can drop them from localStorage -- clears bloat from photos
   cached before this session / before they were flagged. For each order photo
   that still carries img + localId but isn't marked _idbBacked, confirm the
   bytes are in IDB, THEN flag it (never flag before the write is confirmed, so
   a photo whose IDB write fails keeps its localStorage copy). Best-effort and
   idempotent; a no-op when IndexedDB isn't usable (bytes just stay as before).
   Newly-added photos are flagged at capture time (addPhotosFromFiles); this
   handles the rest. */
async function offloadPhotoBytesToIdb(){
  if (typeof window === "undefined" || !window.indexedDB) return false;
  var db = loadDb();
  var orders = db.orders || {};
  var changed = false;
  for (var id in orders){
    var o = orders[id];
    var ph = o && o.photos;
    if (!ph || !ph.length) continue;
    for (var i = 0; i < ph.length; i++){
      var p = ph[i];
      if (!p || !p.img || p._idbBacked || !p.localId) continue;
      try{ await idbPutPhoto(p.localId, p.img); p._idbBacked = true; changed = true; }catch(e){}
    }
  }
  if (changed) saveDb(db); // leanDbReplacer now drops the freshly-flagged bytes
  return changed;
}

/* ================= offline-first: sync queue =================
   Tracks work orders with local changes not yet confirmed saved to the
   cloud. saveOrder() already writes locally FIRST, before any network
   attempt (existing, correct behavior, untouched) -- this queue is what
   turns "the cloud save failed, tell the tech to manually retry" into
   "retry automatically the moment connectivity returns," and is also what
   the visible sync-status indicator (renderSyncStatus() below) reads
   from. One entry per work order id -- saving the same order twice while
   offline just updates its own queue entry. Safe to retry any number of
   times: cloudSaveOrder() is a full, idempotent .set() of current state
   (see its own CRITICAL DATA-LOSS GUARD) -- replaying it never double-
   posts or duplicates a photo, it just re-asserts the same end state. */
var SYNC_QUEUE_KEY = "roofops_sync_queue_v1";
function loadSyncQueue(){
  try{
    var raw = localStorage.getItem(SYNC_QUEUE_KEY);
    return raw ? JSON.parse(raw) : {};
  }catch(e){ return {}; }
}
function saveSyncQueueRaw(q){
  /* Queue metadata only (ids/labels/timestamps/small error strings) --
     never photo bytes -- so this is never expected to hit the quota that
     motivated the IndexedDB layer above. */
  try{ localStorage.setItem(SYNC_QUEUE_KEY, JSON.stringify(q)); }catch(e){ console.warn("sync queue metadata save failed", e); }
}
function markPendingSync(orderId, jobLabel){
  var q = loadSyncQueue();
  var existing = q[orderId];
  q[orderId] = {
    jobLabel: jobLabel || (existing && existing.jobLabel) || orderId,
    queuedAt: (existing && existing.queuedAt) || Date.now(),
    attempts: (existing && existing.attempts) || 0,
    lastError: null
  };
  saveSyncQueueRaw(q);
  renderSyncStatus();
}
function markSynced(orderId){
  var q = loadSyncQueue();
  if (q[orderId]){ delete q[orderId]; saveSyncQueueRaw(q); }
  renderSyncStatus();
}
function markSyncFailed(orderId, err){
  var q = loadSyncQueue();
  if (!q[orderId]) return;
  q[orderId].attempts = (q[orderId].attempts || 0) + 1;
  q[orderId].lastError = (err && err.message) ? err.message : String(err);
  q[orderId].lastAttemptAt = Date.now();
  saveSyncQueueRaw(q);
  renderSyncStatus();
}
/* Loud on purpose (Mark: "never a silent failure -- that's the pattern
   that's bitten us repeatedly"). A queue entry that's failed this many
   times in a row is treated as PERMANENTLY failed, not silently retried
   forever in the background -- surfaced with its own persistent status
   line so it can't be missed, distinct from the routine "offline, will
   sync" state. Does not remove it from the queue (still worth a manual
   retry once whatever's wrong is fixed), just changes how it's shown. */
var SYNC_PERMANENT_FAILURE_THRESHOLD = 6;
function renderSyncStatus(){
  var host = document.getElementById("sync-status-bar");
  if (!host) return;
  var q = loadSyncQueue();
  var ids = Object.keys(q);
  if (!ids.length){
    host.style.display = "none";
    host.innerHTML = "";
    return;
  }
  var failedHard = ids.filter(function(id){ return (q[id].attempts || 0) >= SYNC_PERMANENT_FAILURE_THRESHOLD; });
  var pending = ids.filter(function(id){ return (q[id].attempts || 0) < SYNC_PERMANENT_FAILURE_THRESHOLD; });
  host.style.display = "";
  var parts = [];
  if (pending.length){
    parts.push('<div>' + (navigator.onLine ? "🔄 Syncing" : "📴 Offline") + " — " + pending.length +
      " item" + (pending.length === 1 ? "" : "s") + " saved on this device, will sync when you have signal." +
      ' <button class="btn" style="padding:2px 8px;font-size:12px" onclick="tryFlushSyncQueue()">Retry now</button></div>');
  }
  if (failedHard.length){
    parts.push('<div style="color:#D64545;font-weight:600">⚠️ ' + failedHard.length +
      " item" + (failedHard.length === 1 ? "" : "s") + " couldn't be synced after repeated tries — " +
      failedHard.map(function(id){ return esc(q[id].jobLabel || id); }).join(", ") +
      '. Data is safe on this device. Check your connection, then ' +
      '<button class="btn" style="padding:2px 8px;font-size:12px" onclick="tryFlushSyncQueue()">Retry now</button>.</div>');
  }
  host.innerHTML = parts.join("");
}
/* Reconstructs enough of a queued order to retry cloudSaveOrder() for it,
   even when it's not the order currently open in the editor -- reads the
   locally-cached copy (loadDb().orders[id]), recovering any photo bytes
   pruning may have stripped from THAT copy via idbRecoverPhotoBytes()
   first (see comment there). If the order isn't in the local cache at all
   (shouldn't happen -- saveOrder() always writes it there before ever
   queuing it -- but never trust that blindly), the queue entry is dropped
   rather than left stuck forever on nothing to retry. */
var syncFlushInFlight = false;
async function tryFlushSyncQueue(){
  if (syncFlushInFlight || !fdb || !navigator.onLine) return;
  var q = loadSyncQueue();
  var ids = Object.keys(q);
  if (!ids.length) return;
  syncFlushInFlight = true;
  try{
    for (var i = 0; i < ids.length; i++){
      var id = ids[i];
      var db = loadDb();
      var stored = db.orders[id];
      if (!stored){ markSynced(id); continue; }
      try{
        await idbRecoverPhotoBytes(stored);
        await cloudSaveOrder(stored);
        await syncPinCorrectionsToHistory(stored);
        await logReportAndHistoryEvent(stored, "Saved", null, undefined);
        markSynced(id);
        if (typeof renderSaved === "function") renderSaved();
      }catch(e){
        if (e && e.__conflict){
          /* The cloud holds a newer version than this device's QUEUED copy.
             Don't keep trying to overwrite it -- that's exactly the stale-copy
             clobber loop that resurrected deleted photos. Remove it from the
             queue (the local copy stays in db.orders for the tech to reopen)
             and tell them, rather than retrying forever. */
          markSynced(id);
          toast("A newer version of “" + (q[id].jobLabel || id) + "” was saved on another device — this device's older copy wasn't uploaded. Reopen it to get the latest.");
          if (typeof renderSaved === "function") renderSaved();
        } else {
          markSyncFailed(id, e);
        }
      }
    }
  } finally {
    syncFlushInFlight = false;
  }
}
/* Backoff: doesn't hammer the network or Firestore on every tick if
   something's genuinely still down -- delay grows with attempts (5s, 10s,
   20s... capped at 2min), reset to immediate the moment a real 'online'
   event fires (that's a real signal, not a guess). */
var syncPollTimer = null;
function scheduleSyncPoll(){
  if (syncPollTimer) return;
  syncPollTimer = setInterval(function(){
    var q = loadSyncQueue();
    var ids = Object.keys(q);
    if (!ids.length) return;
    var maxAttempts = ids.reduce(function(m, id){ return Math.max(m, q[id].attempts || 0); }, 0);
    var delayMs = Math.min(5000 * Math.pow(2, maxAttempts), 120000);
    var dueAt = ids.reduce(function(min, id){ return Math.min(min, (q[id].lastAttemptAt || 0)); }, Infinity);
    if (dueAt === Infinity || Date.now() - dueAt >= delayMs) tryFlushSyncQueue();
  }, 5000);
}
window.addEventListener("online", function(){ renderSyncStatus(); tryFlushSyncQueue(); });
window.addEventListener("offline", function(){ renderSyncStatus(); });
document.addEventListener("visibilitychange", function(){
  if (document.visibilityState === "visible") tryFlushSyncQueue();
});
scheduleSyncPoll();
/* Mark: "warn before leaving with unsynced work." Standard beforeunload
   confirmation -- browsers show their own generic text regardless of the
   returnValue string's content (a security/spam-prevention restriction,
   not a bug here), but setting it is what actually triggers the prompt at
   all. */
window.addEventListener("beforeunload", function(e){
  var q = loadSyncQueue();
  if (Object.keys(q).length){
    e.preventDefault();
    e.returnValue = "";
  }
});
/* Mark: "a tech must be able to open RoofOps on a dead-zone roof and have
   it work at all." See sw.js for the actual cache strategy (network-first,
   cache as fallback -- never stuck on a stale deploy while online).
   Registered from a plain <script> in index.html's init block, right after
   updateAdminUI() -- kept as a real function here (not inline there) so
   the shared file's footprint for this feature is a single line. */
function registerServiceWorker(){
  if (!("serviceWorker" in navigator)) return;
  navigator.serviceWorker.register("/sw.js").catch(function(e){
    console.warn("Service worker registration failed (app still works online, just won't have an offline app shell)", e);
  });
}
/* A report's pins are a frozen snapshot by design (see DEV_NOTES.md) so an
   already-sent PDF's content never silently changes. But a pin's *location*
   isn't part of that content \u2014 it's GPS accuracy metadata a tech should be
   able to fix without re-issuing paperwork. So a plain Save also patches
   the location on any existing report(s) that already reference a finding,
   in place, leaving everything else about those reports (summary text,
   photo_ids, warranty, etc.) exactly as originally recorded. Only touches
   findings that already have a pin entry in a given event \u2014 never adds a
   pin to a report that didn't have one. */
async function syncPinCorrectionsToHistory(o){
  if (!fdb) return;
  try{
    var qs = await fdb.collection("building_history_events").where("workOrderId", "==", o.id).get();
    if (qs.empty) return;
    var batch = fdb.batch(), any = false;
    qs.forEach(function(doc){
      var pins = doc.data().pins || [];
      var changed = false;
      var newPins = pins.map(function(p){
        var f = (o.findings || []).find(function(x){ return x.id === p.finding_id; });
        if (!f || !f.pin) return p;
        if (f.pin.lat !== p.lat || f.pin.lng !== p.lng || f.pin.x !== p.x || f.pin.y !== p.y || f.pin.source !== p.source){
          changed = true;
          return Object.assign({}, p, { lat: f.pin.lat, lng: f.pin.lng, x: f.pin.x, y: f.pin.y, source: f.pin.source });
        }
        return p;
      });
      if (changed){ batch.update(doc.ref, { pins: newPins }); any = true; }
    });
    if (any) await batch.commit();
  }catch(e){ console.warn("pin correction sync failed", e); }
}
function saveOrder(opts){
  opts = opts || {};
  var o = collect();
  /* No pre-save gate on photo fields. Captions and finding assignment are
     OPTIONAL — a report/work order must ALWAYS be savable, captions or not
     (Mark: he got stuck, unable to save an edited leak report because its
     photos had no captions). This used to block the explicit Save whenever a
     findings-type report (Leak/Service, Inspection, Warranty) had any
     un-captioned OR un-assigned photo. That was doubly wrong: it blocked the
     SAFE action (Save) while the quiet auto-saves behind Email/Share/Download
     let an identical report go OUT the door — you could send it but not save
     it. Any caption/finding quality nudge belongs on the send/export path or
     as a non-blocking hint, never blocking Save. See "Caption + finding
     enforcement" in DEV_NOTES.md. */
  currentId = o.id;
  var db = loadDb();
  /* Carry the clobber-guard base forward across collect() (which rebuilds the
     order from the form and doesn't know about it). The previously-stored copy
     -- placed here by an earlier save or by loadOrder() -- holds the base this
     edit descends from. A brand-new order has none (0 -> unguarded). */
  o._cloudBaseSavedAt = (db.orders[o.id] && db.orders[o.id]._cloudBaseSavedAt) || 0;
  db.orders[o.id] = o;
  db.index = db.index.filter(function(e){ return e.id !== o.id; });
  db.index.unshift({ id:o.id, jobName:o.jobName || "(untitled)", jobNo:o.jobNo,
    location:o.location, serviceDate:o.serviceDate, savedAt:Date.now() });
  pruneCachedPhotoDrafts(db);
  var localOk = saveDb(db);
  if (localOk) drawSaved();
  /* Offload any not-yet-flagged cached bytes into IndexedDB so localStorage
     stays lean (Phase 1). Fire-and-forget: never delays the save, and it
     re-persists a leaner db itself only if it moved anything. */
  if (localOk) offloadPhotoBytesToIdb();
  /* localOnly (see debouncedLocalAutosave() below) is the "persist
     continuously, not just on submit" half of offline-first -- pure local
     safety net, deliberately never touches the network or the sync queue
     itself. If this order already has real unsynced changes queued from a
     previous explicit Save, that queue entry is left exactly as it is;
     this just makes sure the LATEST version of the work is the one
     sitting on the device (and, once online, the one that eventually
     syncs) even if the tech never gets to tap Save again before losing
     the tab. */
  if (opts.localOnly) return Promise.resolve(localOk);
  if (fdb){
    if (!opts.quiet) toast("Saving to cloud\u2026");
    /* Queued the moment a real (non-localOnly) save attempt starts, not
       only after a failure -- this is what makes the cloud write a
       background sync CONCERN rather than a one-shot action the tech must
       personally see through: if the tab dies mid-request, closes before
       the response comes back, or this exact attempt fails, the order is
       already sitting in the queue for tryFlushSyncQueue() to pick up the
       moment connectivity is confirmed, with no separate "did that save
       actually finish" step for the tech to remember. */
    markPendingSync(o.id, o.jobName);
    /* FIX 1 (stable building identity): resolve/create the customer +
       building BEFORE the doc write so the ids are stored ON the workorder
       doc itself — from then on every reader follows the id, not the
       recomputed name slug. Never blocks the save: ensureCustomerAndBuilding
       already swallows its own Firestore errors and just returns whatever
       identity the order carried. */
    return ensureCustomerAndBuilding(o).then(function(ids){
      if (ids.buildingId){ o.buildingId = ids.buildingId; currentBuildingId = ids.buildingId; }
      if (ids.customerId){ o.customerId = ids.customerId; currentCustomerId = ids.customerId; }
      return cloudSaveOrder(o);
    }).then(function(){
      return syncPinCorrectionsToHistory(o);
    }).then(function(){
      /* Building History used to only get an entry once a PDF was
         Downloaded/Emailed/Shared -- a work order Saved (findings, pins,
         photos and all) but never exported left NO record at all, which is
         exactly what happened to Mark's real Tri-Delta leak report. Every
         save now creates/updates that same building_history_events doc
         (evt_<id>, same upsert-by-id as the PDF actions below) so field
         work shows up immediately, export or not. See "Building History on
         Save" in DEV_NOTES.md. */
      return logReportAndHistoryEvent(o, "Saved", null, undefined);
    }).then(function(){
      if (!opts.quiet) toast("Saved to cloud \u2713 \u2014 visible on all your devices");
      markSynced(o.id);
      renderSaved();
      return true;
    }).catch(function(e){
      if (e && e.__conflict){
        /* A newer version exists in the cloud (another device saved since this
           copy was loaded). Retrying would only keep losing to it, so DON'T
           keep it queued -- drop it from the sync queue (the local copy stays
           in db.orders for the tech to reopen) and say so plainly. This is the
           opposite of a transient failure.

           RESOLVES FALSE (Mark's Flat Branch data loss, summary half): this
           used to resolve localOk (true), so autoSaveBeforeReport() treated a
           REFUSED cloud save as good enough and the email/share went out --
           the sent PDF carried the tech's live edits (his pasted Summary)
           while the cloud doc kept the other device's copy WITHOUT them, and
           because the conflicting copy is deliberately un-queued above, those
           edits were never going to reach the cloud. Sent != saved, silently.
           Now a conflict fails the save's contract outright: every report
           action behind autoSaveBeforeReport() (email/share/mailto) blocks
           until the tech reopens and re-applies. The Save button ignores this
           return value, so its flow (toast + local copy kept) is unchanged.
           A TRANSIENT failure below still resolves localOk on purpose: that
           copy stays queued and WILL reach the cloud, so sent == saved,
           eventually -- not data loss. */
        markSynced(o.id);
        toast(e.message);
        renderSaved();
        return false;
      }
      /* A cloud-save failure must never be silent, even on a quiet autosave
         (e.g. ccImport()'s post-import saveOrder({quiet:true})) -- quiet
         only means "don't announce success," never "hide a real failure."
         Previously this toast was gated behind !opts.quiet, so a failed
         quiet autosave left the tech thinking their work synced when it
         hadn't. See "Silent cloud-save failure" in DEV_NOTES.md.
         markSyncFailed (not markSynced) -- the queue entry stays exactly
         where it is, so tryFlushSyncQueue() keeps retrying automatically;
         the tech does NOT have to remember to come back and tap Save
         again once he has signal. */
      markSyncFailed(o.id, e);
      toast(cloudErrMsg(e) + (navigator.onLine ? "" : " Will retry automatically once you're back online."));
      return localOk;
    });
  } else if (localOk){
    if (!opts.quiet) toast("Saved on this device \u2713 (cloud not loaded \u2014 check internet)");
  }
  return Promise.resolve(localOk);
}
/* ================= offline-first: continuous local autosave =================
   Mark: "work must survive the browser being killed, the phone locking,
   the battery dying. Persist continuously, not on submit." Everything
   above (the sync queue, IndexedDB photo backup) only helps once at least
   one Save has happened -- this is what covers the gap before that first
   tap: any input/change anywhere inside the edit form triggers a debounced
   LOCAL-ONLY save (saveOrder({quiet:true, localOnly:true}) -- see the
   localOnly branch above) a few seconds after the tech stops typing/
   capturing. Deliberately local-only: this must never itself trigger a
   network request every few seconds while someone is mid-sentence on a
   caption -- the explicit Save button remains the only thing that
   attempts a cloud sync directly; this is purely the safety net under it.
   One delegated listener on the edit view (not per-field handlers) so
   every current and future input in that view is covered automatically,
   including fields captured well after this was written. */
var localAutosaveTimer = null;
var LOCAL_AUTOSAVE_DEBOUNCE_MS = 4000;
function scheduleLocalAutosave(){
  if (localAutosaveTimer) clearTimeout(localAutosaveTimer);
  localAutosaveTimer = setTimeout(function(){
    localAutosaveTimer = null;
    if (document.getElementById("view-edit") && document.getElementById("view-edit").style.display !== "none" && currentId){
      saveOrder({ quiet: true, localOnly: true });
    }
  }, LOCAL_AUTOSAVE_DEBOUNCE_MS);
}
document.addEventListener("DOMContentLoaded", function(){
  var editView = document.getElementById("view-edit");
  if (!editView) return;
  editView.addEventListener("input", scheduleLocalAutosave);
  editView.addEventListener("change", scheduleLocalAutosave);
});
async function autoSaveBeforeReport(actionLabel){
  var ok = await saveOrder({ quiet: true });
  if (!ok){
    /* Blocks the report action outright — never email/share a PDF whose
       content isn't durably saved (Mark's Flat Branch summary loss: the
       sent PDF had his pasted Summary, the cloud doc didn't). saveOrder()
       resolves false on a multi-device conflict (edits refused + un-queued)
       and on a failed local write; a merely-queued transient cloud failure
       still proceeds because that copy is durable and will sync. */
    toast("⚠️ NOT " + actionLabel + " — this work order isn't safely saved (see the message above). Your edits are still on this screen; resolve the save first so what you send matches what's stored.");
    return false;
  }
  return true;
}
function loadOrder(id){
  var db = loadDb();
  var local = db.orders[id];
  var localEntry = null;
  db.index.forEach(function(e){ if (e.id === id) localEntry = e; });
  var cloudEntry = null;
  cloudIndexCache.forEach(function(e){ if (e.id === id) cloudEntry = e; });
  /* orderPhotosAreStrippedLocally(): a local copy missing its photo bytes
     must NEVER be treated as "good enough" just because its savedAt
     matches the cloud's -- stripping never bumps that timestamp, so a
     stripped copy and its cloud original can carry the same timestamp
     forever. Always prefer a fresh cloud fetch over a known-stripped local
     copy when there's a connection to get one. See stripPhotoBytes() and
     "PDF/preview missing photos" in DEV_NOTES.md. */
  var needCloud = fdb && cloudEntry &&
    (!local || orderPhotosAreStrippedLocally(local) || (cloudEntry.savedAt || 0) > ((localEntry && localEntry.savedAt) || 0));
  if (needCloud){
    toast("Loading from cloud\u2026");
    cloudFetchOrder(id).then(function(o){
      if (o){
        fill(o); showView("edit"); toast("Loaded from cloud \u2713");
        /* Viewing \u2260 caching: keep everything but the photo bytes locally
           (see the "storage" section above) so this doesn't silently refill
           localStorage from just opening old reports. */
        var db2 = loadDb();
        db2.orders[o.id] = stripPhotoBytes(o);
        db2.index = db2.index.filter(function(e){ return e.id !== o.id; });
        db2.index.unshift({ id:o.id, jobName:o.jobName || "(untitled)", jobNo:o.jobNo,
          location:o.location, serviceDate:o.serviceDate, savedAt:(cloudEntry.savedAt || Date.now()) });
        saveDb(db2);
      } else if (local){ fill(local); showView("edit"); }
      else toast("Could not find that work order");
    }).catch(function(){
      if (local){ fill(local); showView("edit"); toast("Cloud unavailable \u2014 opened the copy on this device"); }
      else toast("Couldn't load \u2014 check your internet connection");
    });
    return;
  }
  if (local){ fill(local); showView("edit"); toast("Work order loaded"); return; }
  if (fdb){
    /* Not in the local cache or the (capped, most-recent-100) cloud index —
       still worth a direct fetch by id, e.g. when opened from an older
       building-history pin that falls outside that cache. */
    toast("Loading from cloud…");
    cloudFetchOrder(id).then(function(o){
      if (o){
        fill(o); showView("edit"); toast("Loaded from cloud ✓");
        var db2 = loadDb();
        db2.orders[o.id] = stripPhotoBytes(o);
        db2.index = db2.index.filter(function(e){ return e.id !== o.id; });
        db2.index.unshift({ id:o.id, jobName:o.jobName || "(untitled)", jobNo:o.jobNo,
          location:o.location, serviceDate:o.serviceDate, savedAt:Date.now() });
        saveDb(db2);
      } else toast("Could not find that work order");
    }).catch(function(){ toast("Couldn't load — check your internet connection"); });
    return;
  }
  toast("Could not find that work order");
}
/* Admin-only (Mark's access-control change to the Saved view — see
   "Saved view access control" in DEV_NOTES.md). The button that calls this
   is already hidden for non-admins (see drawSaved()), but this check is
   the real gate — same defense-in-depth pattern as deleteBuildingAdmin()
   and every other admin-only action in this file: someone opening
   devtools and calling this directly should hit the same wall a hidden
   button would. */
function deleteOrder(id){
  if (!isAdmin){ toast("Admin mode required to delete."); return; }
  if (!confirm("Delete this work order everywhere? This can't be undone.")) return;
  var db = loadDb();
  delete db.orders[id];
  db.index = db.index.filter(function(e){ return e.id !== id; });
  saveDb(db);
  cloudIndexCache = cloudIndexCache.filter(function(e){ return e.id !== id; });
  drawSaved();
  if (fdb){
    cloudDeleteOrder(id).then(function(){ toast("Deleted everywhere \u2713"); })
      .catch(function(){ toast("Deleted on this device \u2014 cloud copy may remain (check internet)"); });
  } else toast("Deleted on this device");
}
function mergedIndex(){
  var db = loadDb();
  var map = {};
  db.index.forEach(function(e){ map[e.id] = e; });
  cloudIndexCache.forEach(function(e){
    if (!map[e.id] || (e.savedAt || 0) >= (map[e.id].savedAt || 0)) map[e.id] = e;
  });
  var arr = Object.keys(map).map(function(k){ return map[k]; });
  arr.sort(function(a, b){ return (b.savedAt || 0) - (a.savedAt || 0); });
  return arr;
}
function drawSaved(){
  var list = mergedIndex();
  document.getElementById("saved-count").textContent = list.length;
  var status = document.getElementById("cloud-status");
  if (status) status.textContent = fdb
    ? "Cloud sync ON \u2014 work orders are shared across all devices using this link."
    : "Cloud sync OFF (couldn't reach the internet) \u2014 saves stay on this device until you're back online.";
  var host = document.getElementById("saved-list");
  if (!list.length){
    host.innerHTML = '<div class="empty">No saved work orders yet. Fill one out on the Edit tab and hit Save.</div>';
    return;
  }
  host.innerHTML = list.map(function(e){
    /* "Leak – No Job" chip: the index entry only carries jobName (no
       Foundation fields), so this matches by name alone — the edit-form
       banner (isLeakNoJobOrder(), js/workorders.js — loads after this
       file, hence the typeof guard) is the authoritative view that also
       clears on a real Foundation link. */
    var noJobChip = (typeof isLeakNoJobName === "function" && isLeakNoJobName(e.jobName)) ?
      ' <span style="background:#FFF3E0;color:#8A5A00;font-size:11px;font-weight:700;padding:2px 7px;border-radius:4px;white-space:nowrap">⚠️ No Job # yet</span>' : '';
    return '<div class="saved-item"><div class="info">' +
      '<div class="name">' + esc(e.jobName) + (e.jobNo ? ' <span>#' + esc(e.jobNo) + '</span>' : '') + noJobChip + '</div>' +
      '<div class="meta">' + esc(e.location || "") + (e.serviceDate ? ' \u00B7 ' + esc(e.serviceDate) : '') +
      (e.cloud ? ' \u00B7 \u2601' : '') +
      (e.lastEmailedAt ? ' \u00B7 \uD83D\uDCE7 Emailed ' + fmtTs(e.lastEmailedAt) : '') + '</div></div>' +
      '<button class="btn" onclick="loadOrder(\'' + e.id + '\')">Open</button>' +
      /* Delete is admin-only (Mark's access-control change) -- a
         non-admin's Saved view only ever offers Open. Export was removed
         entirely (Mark: "I don't need an export button at all"), not just
         admin-gated -- see "Saved view access control" and "Export
         button removed" in DEV_NOTES.md. */
      (isAdmin ? '<button class="btn danger" onclick="deleteOrder(\'' + e.id + '\')">Delete</button>' : '') +
      '</div>';
  }).join("");
}
function renderSaved(){
  drawSaved();
  if (fdb){
    cloudFetchIndex().then(function(arr){
      cloudIndexCache = arr;
      drawSaved();
    }).catch(function(e){
      var status = document.getElementById("cloud-status");
      if (status) status.textContent = "Couldn't reach cloud storage \u2014 " +
        ((e && e.message && e.message.indexOf("permission") > -1)
          ? "Firestore rules are blocking access (they may have expired)."
          : "showing work orders saved on this device only.");
    });
  }
}

/* ================= views ================= */
var currentViewName = "home"; /* mirrors showView()'s v -- used by Send
  Feedback to auto-capture which screen the tester was on. See "Send
  Feedback" in DEV_NOTES.md. */
function showView(v){
  if (v === "admin" && !isAdmin){
    v = "edit";
  }
  if (v === "estimator" && !(currentAuthClaims && currentAuthClaims.owner === true)){
    v = "edit";
  }
  if (v === "servicemanager" && !canServiceManage()){
    v = "edit";
  }
  currentViewName = v;
  /* "home" has no header tab (reached via "+ New", the empty-state button
     in Building History, or tapping the logo) — every other view still
     keeps its tab exactly as before. */
  ["home","edit","preview","saved","history","reports","estimator","roofmapper","dpr","servicemanager","admin"].forEach(function(name){
    var viewEl = document.getElementById("view-" + name);
    if (viewEl) viewEl.style.display = (name === v ? "" : "none");
    var tabEl = document.getElementById("tab-" + name);
    if (tabEl) tabEl.classList.toggle("active", name === v);
  });
  if (v === "home") renderHomeTiles();
  if (v === "preview") renderDoc();
  if (v === "saved") renderSaved();
  if (v === "history") renderHistoryList();
  if (v === "reports"){ renderReportsList(); if (isAdmin){ loadFeedbackBacklog(); loadAuditLogBacklog(); } }
  if (v === "estimator" && typeof estimatorOnShow === "function") estimatorOnShow();
  if (v === "roofmapper") rmOnShow();
  if (v === "dpr" && typeof dprOnShow === "function") dprOnShow();
  if (v === "servicemanager" && typeof smOnShow === "function") smOnShow();
  if (v === "admin" && typeof rolesAdminOnShow === "function") rolesAdminOnShow();
  window.scrollTo(0,0);
  if (v === "edit" && pendingPinFindingId){
    var fid = pendingPinFindingId;
    pendingPinFindingId = null;
    openPinModal(fid);
  }
  /* CompanyCam PDF backfill (⟳ on a report row) — same load-then-act
     pattern as the pin jump above; no-ops unless
     backfillReportPdfToCompanyCam() just loaded this order. See
     runPendingCcPdfBackfill() in js/history.js. */
  if (v === "edit" && typeof runPendingCcPdfBackfill === "function") runPendingCcPdfBackfill();
}

